    {'id': 'CALUS-MCP-SCAN-074', 'name': 'mcp-server-capability-enumeration', 'severity': 'HIGH', 'category': 'mcp_security', 'message': 'MCP server capability enumeration attempt detected', 'patterns': ['(?i)(?:list|enumerate|discover|scan|probe)\\s+(?:all|available|exposed)\\s+(?:mcp\\s+)?(?:tools?|capabilities?|functions?|endpoints?|resources?)\\s+(?:on|from|in)\\s+(?:the\\s+)?(?:mcp\\s+server|tool\\s+server|server)', '(?i)(?:what\\s+(?:tools?|capabilities?|functions?|actions?)\\s+(?:do\\s+you|can\\s+you|are\\s+(?:you\\s+)?(?:able|available))|show\\s+me\\s+(?:all|your)\\s+(?:tools?|capabilities?|functions?))', '(?i)(?:tools\\/list|capabilities\\/list|mcp\\.list_tools|server\\.list_tools|list_capabilities)\\s*\\(']},
