    {'id': 'CALUS-MCP-SCAN-078', 'name': 'mcp-webhook-manipulation-callback-hijack', 'severity': 'HIGH', 'category': 'mcp_security', 'message': 'MCP webhook URL manipulation: user-controlled webhook endpoint without validation', 'patterns': ['(?i)(?:override|replace|change|modify|redirect)\\s+(?:the\\s+)?(?:webhook|callback|notification|event)\\s+(?:url|endpoint|destination|target)\\s+(?:to|with)\\s+(?:my|attacker|external|different)', '(?i)(?:webhook|callback).*(?:url|endpoint)\\s*=\\s*(?:request\\.|req\\.|user_|input|param)(?!.*(?:validate|allowlist|whitelist|re\\.match|urlparse))', '(?i)(?:mcp|tool).*(?:webhook|notification|event|callback).*(?:send|forward|post).*(?:attacker|external|http://[^l]|https://(?!(?:localhost|127)))']},
    {'id': 'CALUS-MCP-SCAN-079', 'name': 'mcp-ssrf-tool-internal-network-probe', 'severity': 'CRITICAL', 'category': 'mcp_security', 'message': 'MCP SSRF: cloud metadata or internal network endpoint targeted via tool fetch capability', 'patterns': ['(?i)(?:fetch|get|request|access|browse|visit)\\s+(?:url|page|endpoint|resource)\\s*[=:]\\s*["\']?(?:http://(?:169\\.254\\.169\\.254|metadata\\.google\\.internal|100\\.100\\.100\\.200|127\\.0\\.0\\.1|localhost|10\\.|192\\.168\\.|172\\.(?:1[6-9]|2[0-9]|3[01])\\.))[^"\'\\s]*', '(?i)(?:use|call|invoke)\\s+(?:the\\s+)?(?:mcp|web|http|fetch)\\s+tool\\s+(?:to\\s+)?(?:access|request|fetch|get)\\s+(?:the\\s+)?(?:metadata|internal|localhost|cloud)\\s+(?:endpoint|service|url|api)', '(?i)mcp.*(?:fetch|browse|http|request).*(?:169\\.254\\.169\\.254|metadata\\.google\\.internal|100\\.100\\.100\\.200)']},
