    {'id': 'CALUS-MCP-SCAN-081', 'name': 'mcp-tool-argument-injection-cross-boundary', 'severity': 'CRITICAL', 'category': 'mcp_security', 'message': "Cross-tool argument injection: output from one MCP tool injected unsanitized into another tool's arguments", 'patterns': ['(?i)(?:inject|smuggle|embed|insert)\\s+(?:into|in)\\s+(?:the\\s+)?(?:mcp\\s+)?tool\\s+(?:argument|parameter|input)\\s+(?:from|via|through)\\s+(?:another|different|external|untrusted)\\s+(?:mcp\\s+)?tool', '(?i)(?:tool_a|first_tool|source_tool).*(?:output|result).*(?:tool_b|second_tool|target_tool).*(?:input|argument|parameter).*(?:inject|manipulate|poison|smuggle)', '(?i)(?:cross.tool|inter.tool|tool.to.tool)\\s+(?:argument|parameter|input)\\s+(?:injection|smuggling|manipulation|poisoning)']},
