    {'id': 'CALUS-MCP-SCAN-085', 'name': 'mcp-rate-limiting-bypass-endpoint', 'severity': 'MEDIUM', 'category': 'mcp_security', 'message': 'MCP rate limit bypass attempt via distributed requests or credential rotation', 'patterns': ['(?i)(?:bypass|evade|circumvent|avoid)\\s+(?:the\\s+)?(?:rate\\s+limit|throttling|quota|restriction)\\s+(?:on|for)\\s+(?:the\\s+)?(?:mcp|tool)\\s+(?:endpoint|server|api)', '(?i)(?:distributed|parallel|concurrent)\\s+(?:mcp|tool)\\s+(?:calls?|requests?|invocations?)\\s+(?:to|in\\s+order\\s+to)\\s+(?:bypass|evade|exceed|circumvent)\\s+(?:rate\\s+limit|throttling|quota)', '(?i)(?:rotate|cycle|switch)\\s+(?:between\\s+)?(?:api\\s+keys?|tokens?|credentials?|identities?|ip\\s+addresses?)\\s+(?:to\\s+)?(?:bypass|evade|circumvent)\\s+(?:rate\\s+limit|throttling)\\s+(?:on|for)\\s+(?:mcp|tool)']},
