    {'id': 'CALUS-MCP-SCAN-087', 'name': 'mcp-cross-origin-tool-invocation', 'severity': 'HIGH', 'category': 'mcp_security', 'message': 'Cross-origin MCP tool invocation: CORS misconfiguration enables unauthorized cross-site tool access', 'patterns': ['(?i)(?:cross.origin|cross.domain|cors)\\s+(?:mcp|tool)\\s+(?:invocation|call|access|request)', '(?i)(?:invoke|call|access)\\s+(?:mcp\\s+)?tool\\s+(?:from\\s+)?(?:a\\s+)?(?:different|external|third.party|untrusted)\\s+(?:origin|domain|site)\\s+(?:without|bypassing|ignoring)\\s+(?:cors|same.origin|origin\\s+check)', '(?i)(?:Access-Control-Allow-Origin|CORS)\\s*(?:\\*|=\\s*["\']\\*["\']).*(?:mcp|tool|plugin|server)(?!.*(?:credentials\\s*=\\s*false|allow.credentials\\s*=\\s*false))']},
