    {'id': 'CALUS-MCP-SCAN-140', 'name': 'mcp-dpt-cross-origin-violation', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Cross-origin or cross-server access configuration may allow violation of MCP trust boundaries.', 'patterns': ['(?i)(?:Access-Control-Allow-Origin|Origin)\\s*[:=]\\s*[\'"]?\\*[\'"]?']},
    {'id': 'CALUS-MCP-SCAN-141', 'name': 'mcp-dpt-tool-squatting-amplification', 'severity': 'low', 'category': 'mcp_security', 'message': 'Potential tool squatting or typo-squatting pattern detected in MCP configuration.', 'patterns': ['(?i)\\b(?:squat|typo|homograph|lookalike|similar)\\s+(?:tool|server|name|package)\\b', '(?i)\\b(?:mcp|tool)[\\s_-]*(?:squat|typo|homograph)\\b']},
    {'id': 'CALUS-MCP-SCAN-142', 'name': 'mcp-dpt-resource-type-confusion', 'severity': 'low', 'category': 'mcp_security', 'message': 'Potential resource type confusion or impersonation detected.', 'patterns': ['(?i)\\b(?:declare|expect|set)\\s+type\\b.{0,40}\\b(?:number|string|boolean|object)\\b.{0,40}\\b(?:but|actual)\\b.{0,40}\\b(?:string|number|boolean|object)\\b']},
    {'id': 'CALUS-MCP-SCAN-143', 'name': 'mcp-dpt-binary-payload-delivery', 'severity': 'low', 'category': 'mcp_security', 'message': 'Potential binary payload delivery pattern in MCP interaction.', 'patterns': ['(?i)\\b(?:binary|payload|exploit|shellcode)\\s+(?:deliver|inject|load|exec)\\b', '(?i)(?:data:)?(?:base64|binary)\\s+(?:content|payload)\\b.{0,40}\\b(?:exec|run|write|save)\\b']},
    {'id': 'CALUS-MCP-SCAN-144', 'name': 'mcp-dpt-multi-tool-cooperation', 'severity': 'low', 'category': 'mcp_security', 'message': 'Potential multi-tool cooperation or propagation pattern detected.', 'patterns': ['(?i)\\b(?:tool1|tool2|chain)\\b.{0,60}\\b(?:exfil|send|post|upload)\\b']},
    {'id': 'CALUS-MCP-SCAN-145', 'name': 'mcp-dpt-registry-malicious-tool-registration', 'severity': 'low', 'category': 'mcp_security', 'message': 'Registry configuration may allow malicious tool registration.', 'patterns': ['(?i)\\b(?:register|publish|upload)\\s+(?:tool|server|plugin)\\b.{0,40}\\b(?:untrusted|malicious|external|attacker)\\b', '(?i)\\b(?:allow|enable)\\s+(?:anyone|everyone|public)\\s+(?:register|publish)\\b']},
    {'id': 'CALUS-MCP-SCAN-146', 'name': 'mcp-dpt-endpoint-exposure-scanner', 'severity': 'high', 'category': 'mcp_security', 'message': 'Detected MCP endpoint bound to all interfaces without authentication, risking unauthorized access to server capabilities.', 'patterns': ['(?i)\\b(?:no auth|no authentication|disable auth|allow all)\\b.{0,40}\\b(?:mcp|tool|server)\\b']},
    {'id': 'CALUS-MCP-SCAN-147', 'name': 'mcp-dpt-slash-command-overlap-scanner', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected overlapping slash command handlers that may allow unauthorized command execution via malicious command registration.', 'patterns': ['(?i)\\bregister_slash_command.{0,40}\\b(?:system|exec|shell|override)\\b', '(?i)\\b(?:command|slash).{0,40}(?:handler|action).{0,40}[:=].{0,40}[\'"]\\/']},
    {'id': 'CALUS-MCP-SCAN-148', 'name': 'mcp-dpt-schema-inconsistency-scanner', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected potential schema inconsistency between tool declaration and implementation, which can lead to parameter injection or data leaks.', 'patterns': ['(?i)\\b(?:tool|function|action).{0,40}(?:schema|input|params).{0,40}(?:mismatch|inconsistent)\\b']},
    {'id': 'CALUS-MCP-SCAN-149', 'name': 'mcp-dpt-remote-code-execution-scanner', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected potential remote code execution path in MCP server where tool inputs are passed to dynamic code execution functions.', 'patterns': ['(?i)\\b(?:subprocess|os\\.system|child_process)\\..{0,40}(?:input|args|data)\\b', '(?i)\\b(?:import|execfile|load).{0,40}(?:__import__|importlib)\\.{0,40}(?:input|data)']},
    {'id': 'CALUS-MCP-SCAN-150', 'name': 'mcp-dpt-registry-malicious-tool-registration-scanner', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected potentially malicious tool registration or upload that could compromise the MCP supply chain.', 'patterns': ['(?i)\\bregister_tool.{0,40}\\b(?:backdoor|malicious|inject|steal|exfil)\\b', '(?i)\\b(?:publish|deploy|upload)\\s*.{0,40}\\btool.{0,40}\\b(?:poison|trap|malware)\\b']},
    {'id': 'CALUS-MCP-SCAN-152', 'name': 'mcp-dpt-server-resource-exhaustion-scanner', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected potential resource exhaustion pattern that could be exploited for denial of service against MCP server.', 'patterns': ['(?i)\\b(?:async|await|promise).{0,40}(?:all|race).{0,60}\\b(?:unlimited|no_limit|infinite)\\b', '(?i)\\b(?:thread.executor|ProcessPoolExecutor|concurrent.futures).{0,40}\\b(?:unbounded|max_workers.{0,10}0)\\b']},
    {'id': 'CALUS-MCP-SCAN-153', 'name': 'mcp-dpt-insecure-server-authentication-scanner', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected insecure authentication configuration in MCP server that may allow unauthorized access.', 'patterns': ['(?i)\\b(?:api_key|secret|password).{0,40}[:=]\\s*[\'"][\'"].{0,80}(?:hardcoded|default|placeholder)']},
    {'id': 'CALUS-MCP-SCAN-154', 'name': 'mcp-dpt-tool-squatting-amplification-scanner', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected potential tool name squatting that could be used to trick agents into using malicious tools.', 'patterns': ['(?i)\\b(?:legitimate|popular|trusted)_tool_name.{0,40}(?:typo|misspell)\\b']},
    {'id': 'CALUS-MCP-SCAN-155', 'name': 'mcp-dpt-resource-type-confusion-scanner', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected potential resource type confusion where content type does not match actual resource content.', 'patterns': ['(?i)\\b(?:content.type|mime|media).{0,40}(?:text|application|image).{0,40}\\b(?:script|exec|shell)\\b', '(?i)\\bserve_resource.{0,40}\\b(?:headers).{0,40}\\b(?:Content-Type).{0,40}\\bapplication/json\\b.{0,40}false']},
    {'id': 'CALUS-MCP-SCAN-156', 'name': 'mcp-dpt-binary-payload-delivery-scanner', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected potential binary payload delivery via MCP resource that could execute arbitrary code.', 'patterns': ['(?i)\\b(?:exec|run|load).{0,40}(?:binary|blob|byte).{0,40}(?:resource|data|content)\\b']},
    {'id': 'CALUS-MCP-SCAN-157', 'name': 'mcp-dpt-multi-tool-cooperation-scanner', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected potential multi-tool cooperation pattern that could enable coordinated malicious actions over multiple tools.', 'patterns': ['(?i)\\b(?:chain|sequence|orchestrate|coordinate|collaborate).{0,80}\\btool.{0,40}\\b(?:attack|malicious|exfil|steal)\\b', '(?i)\\bmulti.tool.{0,40}\\b(?:propagation|cooperation|cascade|workflow)\\b']},
    {'id': 'CALUS-MCP-SCAN-158', 'name': 'mcp-dpt-selection-inducement-scanner', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected tool metadata that may induce LLM to select a malicious tool over legitimate alternatives.', 'patterns': ['(?i)\\b(?:tool|function|action)\\s*(?:name|title).{0,40}(?:ignore|skip|avoid).{0,40}(?:other|original|legitimate)\\b']},
    {'id': 'CALUS-MCP-SCAN-159', 'name': 'mcp-capability-chaining-tool-seq', 'severity': 'high', 'category': 'mcp_security', 'message': 'Potential capability chaining: sequence of read and write tools detected that could enable unauthorized data exfiltration.', 'patterns': ['(?i)tools?\\s*[\\[\\(].{0,40}(?:read[-_]?file|get[-_]?file|fetch[-_]?file).{0,60}(?:send[-_]?mail|write[-_]?file|exfil|upload)']},
    {'id': 'CALUS-MCP-SCAN-160', 'name': 'mcp-tool-version-rollback', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool version rollback configuration detected, which could allow re-introduction of vulnerabilities.', 'patterns': ['(?i)(?:version|rollback|downgrade)\\s*[=:].{0,20}(?:\\d+\\.\\d+\\.\\d+).{0,40}(?:<|\\bolder\\b|\\bprevious\\b|\\brollback\\b)', '(?i)(?:allow|enable|support)\\s*\\w*[-_]?(?:rollback|downgrade|version[-_]?change)']},
    {'id': 'CALUS-MCP-SCAN-161', 'name': 'mcp-sampling-abuse-config', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP server configuration with sampling enabled may allow unauthorized context extraction.', 'patterns': ['(?i)(?:sampling|createMessage)\\s*[=:].{0,40}(?:true|enabled|1|yes)']},
    {'id': 'CALUS-MCP-SCAN-162', 'name': 'mcp-tool-description-structured', 'severity': 'low', 'category': 'mcp_security', 'message': 'Structured tool description pattern detected, aligning with MCPSHIELD recommendation to reduce prompt injection risk.', 'patterns': ['(?i)"function"\\s*:\\s*\\{[^}]*"description"\\s*:\\s*"[^"]{0,300}"[^}]*"parameters"\\s*:\\s*\\{', '(?i)structured_description\\s*[=:].{0,40}(?:true|yes|1)']},
    {'id': 'CALUS-MCP-SCAN-163', 'name': 'mcp-version-rollback-tool-check', 'severity': 'high', 'category': 'mcp_security', 'message': 'Potential MCP tool version rollback detected: version comparison may allow regression to a vulnerable tool version.', 'patterns': ['(?i)\\.version\\b.{0,40}\\.(?:less_than|<=|<|compare)\\s*\\(\\s*[\'"](\\d+\\.?\\d*)[\'"]\\s*\\)', '(?i)rollback\\b.{0,40}\\.(?:version|tool)\\b.{0,40}(?:to\\s+)?[\'"]\\d+\\.\\d+[\'"]']},
    {'id': 'CALUS-MCP-SCAN-164', 'name': 'mcp-capability-escalation-session-pattern', 'severity': 'high', 'category': 'mcp_security', 'message': 'Capability escalation pattern detected: server may be adding tool permissions incrementally across sessions.', 'patterns': ['(?i)add_(?:permission|capability|scope)\\b.{0,40}\\.(?:tool|function)\\b', '(?i)increment(?:_session)?_permissions\\s*\\(\\s*[\'"][^\'"]+[\'"]']},
    {'id': 'CALUS-MCP-SCAN-165', 'name': 'mcp-channel-coercion-insecure-transport', 'severity': 'low', 'category': 'mcp_security', 'message': 'Insecure channel coercion: the code instructs the agent to use an unencrypted transport, which could facilitate data exfiltration.', 'patterns': ['(?i)\\b(?:use|switch|change)_to_insecure\\b.{0,40}\\b(?:channel|transport|protocol)\\b', '(?i)(?:http|unencrypted|plaintext).{0,40}(?:instead_of|rather_than).{0,40}(?:https|encrypted|tls)']},
    {'id': 'CALUS-MCP-SCAN-166', 'name': 'mcp-sampling-abuse-data-extraction', 'severity': 'low', 'category': 'mcp_security', 'message': 'Sampling abuse: MCP server requests LLM sampling with context extraction pattern, potentially exfiltrating host data.', 'patterns': ['(?i)(?:send|extract)_context_to_server.{0,40}(?:sampling|llm)']},
    {'id': 'CALUS-MCP-SCAN-167', 'name': 'mcp-consent-bypass-auto-approve-manipulation', 'severity': 'low', 'category': 'mcp_security', 'message': 'Consent bypass pattern: tool description suggests bypassing user approval, which could be exploited for privilege escalation.', 'patterns': ['(?i)(?:auto-?approve|auto_approve|skip_consent|bypass_approval).{0,60}(?:action|operation|request)', "(?i)(?:no need|not require|don't need).{0,40}(?:user|human|explicit).{0,40}(?:approval|consent|permission)"]},
    {'id': 'CALUS-MCP-SCAN-168', 'name': 'mcp-memory-poisoning-persistent-context-modification', 'severity': 'medium', 'category': 'mcp_security', 'message': "Memory poisoning pattern: code may inject adversarial data into agent's persistent memory, corrupting future reasoning.", 'patterns': ['(?i)(?:modify|overwrite|update).{0,40}(?:memory_|conversation_history|persistent_context)']},
    {'id': 'CALUS-MCP-SCAN-169', 'name': 'mcp-session-hijacking-token-reuse', 'severity': 'high', 'category': 'mcp_security', 'message': 'Session hijacking risk: hardcoded or predictable session tokens may allow attackers to inject commands into active sessions.', 'patterns': ['(?i)session_token\\s*=\\s*[\'"](?:test|123456|admin|default)[\'"]', '(?i)session_id\\s*=\\s*[\'"][^\'"]+[\'"].{0,40}(?:hardcoded|static|predictable|weak)']},
    {'id': 'CALUS-MCP-SCAN-170', 'name': 'mcp-replay-attack-nonce-missing', 'severity': 'low', 'category': 'mcp_security', 'message': 'Replay attack vulnerability: JSON-RPC message missing nonce or timestamp; attacker can re-transmit captured messages.', 'patterns': ['(?i)\\b(?:jsonrpc|mcp).{0,60}(?:message|request|response).{0,40}(?:without|no|missing).{0,40}(?:nonce|timestamp|replay)', '(?i)no_nonce.{0,40}(?:jsonrpc|mcp)', '(?i)timestamp.{0,40}(?:optional|false|none).{0,40}(?:jsonrpc|mcp)']},
    {'id': 'CALUS-MCP-SCAN-171', 'name': 'mcp-version-rollback-detection', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP server version rollback detected: tool version has regressed from approved version.', 'patterns': ['(?i)\\bversion\\s*rollback\\b', '(?i)\\brollbackVersion\\b|\\bversionRegress\\b', '(?i)\\.version\\s*<\\s*approvedVersion\\b']},
    {'id': 'CALUS-MCP-SCAN-172', 'name': 'mcp-capability-escalation-sequential', 'severity': 'low', 'category': 'mcp_security', 'message': 'Capability escalation pattern detected: tool permissions are expanding across sessions.', 'patterns': ['(?i)\\bcapability\\s*escalation\\b', '(?i)\\bscope\\b.{0,40}\\b(?:expand|increase|elevate|escalate)\\b', '(?i)\\bescalatedCapabilities\\b|\\bcapabilityProgression\\b']},
    {'id': 'CALUS-MCP-SCAN-173', 'name': 'mcp-channel-coercion-insecure', 'severity': 'low', 'category': 'mcp_security', 'message': 'Channel coercion attack detected: tool is forcing use of insecure communication channel.', 'patterns': ['(?i)\\bchannel\\s*coercion\\b', '(?i)\\bforceHttp\\b|\\buseHttp\\b|\\bdowngradeProtocol\\b']},
    {'id': 'CALUS-MCP-SCAN-174', 'name': 'mcp-context-bleed-provenance', 'severity': 'low', 'category': 'mcp_security', 'message': 'Context bleed detected: data from one MCP server is influencing a request to another server without authorization.', 'patterns': ['(?i)\\bcontext\\s*bleed\\b', '(?i)\\bdata\\s*(?:from|from)\\s*server.{0,40}\\b(?:to|in)\\s*server\\b', '(?i)\\bleakContext\\b', '(?i)\\bleak\\s*(?:data|context)\\s*(?:across|between)\\b']},
    {'id': 'CALUS-MCP-SCAN-175', 'name': 'mcp-session-hijacking-id-theft', 'severity': 'low', 'category': 'mcp_security', 'message': 'Session hijacking attack detected: session identifier is being captured or injected.', 'patterns': ['(?i)\\bsession\\s*hijack\\b', '(?i)\\b(sessionId|session_token)\\b.{0,40}\\b(?:steal|capture|inject|reuse)\\b', '(?i)\\bhijackSession\\b', '(?i)\\bstealSession\\b']},
    {'id': 'CALUS-MCP-SCAN-176', 'name': 'mcp-replay-attack-nonce', 'severity': 'low', 'category': 'mcp_security', 'message': 'Replay attack detected: JSON-RPC message ID or nonce is reused.', 'patterns': ['(?i)\\b(jsonrpc|message)[_-]?id\\b.{0,40}\\b(?:reuse|repeat|not\\s*unique)\\b', '(?i)\\bnonceMissing\\b|\\bnoNonce\\b']},
    {'id': 'CALUS-MCP-SCAN-177', 'name': 'mcp-cross-protocol-confusion-bridge', 'severity': 'low', 'category': 'mcp_security', 'message': 'Cross-protocol confusion attack detected: agent bridging MCP with another protocol creates semantic gaps.', 'patterns': ['(?i)\\bcross\\s*protocol\\s*confusion\\b', '(?i)\\bprotocolBridge\\b|\\bprotocolConfusion\\b']},
    {'id': 'CALUS-MCP-SCAN-178', 'name': 'mcp-tool-attestation-missing', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool attestation is missing or disabled, enabling tool definition tampering.', 'patterns': ['(?i)\\btoolAttestation\\s*(?:missing|none|null|false|skip)\\b', '(?i)\\bskipAttestation\\b|\\bnoAttestation\\b', '(?i)\\battest\\b.{0,40}\\b(?:false|disabled|none)\\b']},
    {'id': 'CALUS-MCP-SCAN-179', 'name': 'mcp-information-flow-label-missing', 'severity': 'low', 'category': 'mcp_security', 'message': 'Information flow labels are missing or disabled, enabling data leakage across trust domains.', 'patterns': ['(?i)\\binfoFlowLabel\\s*(?:missing|none|null|false)\\b', '(?i)\\bflowLabel\\s*(?:skip|omit|disable)\\b', '(?i)\\bnoFlowControl\\b|\\bdisableFlowTracking\\b']},
    {'id': 'CALUS-MCP-SCAN-180', 'name': 'mcp-security-automaton-bypass', 'severity': 'low', 'category': 'mcp_security', 'message': 'Security automaton bypass detected: runtime policy enforcement is being disabled.', 'patterns': ['(?i)\\bsecurityAutomaton\\s*(?:bypass|disable|stop|pause)\\b', '(?i)\\b(autoSuppress|editAutomaton)\\b.{0,40}\\b(?:false|none|disabled)\\b', '(?i)\\bdisableMonitor\\b|\\bskipPolicyEnforcement\\b']},
    {'id': 'CALUS-MCP-SCAN-181', 'name': 'mcp-tool-definition-mutable', 'severity': 'low', 'category': 'mcp_security', 'message': 'Mutable tool definition detected: tool can change after approval, enabling rug pull attacks.', 'patterns': ['(?i)\\bmutableTool\\b|\\btoolMutate\\b', '(?i)\\bpostApprovalMutation\\b', '(?i)\\bimmutable\\s*:\\s*false\\b|\\bfrozen\\s*:\\s*false\\b']},
    {'id': 'CALUS-MCP-SCAN-182', 'name': 'mcp-tool-shadowing-name-collision', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool shadowing detected: multiple tools with identical or similar names exist, indicating a possible impersonation.', 'patterns': ['(?i)\\btoolShadowing\\b|\\bshadowTool\\b', '(?i)\\bduplicateToolName\\b|\\btoolNameCollision\\b', '(?i)\\bcloneTool\\b.{0,40}\\b(?:name|id)\\b']},
    {'id': 'CALUS-MCP-SCAN-183', 'name': 'mcp-supply-chain-dependency-file', 'severity': 'low', 'category': 'mcp_security', 'message': 'Supply chain compromise detected: malicious dependency is being injected into MCP server.', 'patterns': ['(?i)\\bsupplyChain\\s*compromise\\b', '(?i)\\bmaliciousDependency\\b|\\bpoisonedDependency\\b', '(?i)\\bdependency\\s*(?:from|fetch|download).{0,40}\\b(?:untrusted|http|url)\\b']},
    {'id': 'CALUS-MCP-SCAN-184', 'name': 'mcp-dependency-hijacking-namespace', 'severity': 'low', 'category': 'mcp_security', 'message': 'Dependency hijacking detected: package namespace may have been captured by an attacker.', 'patterns': ['(?i)\\bdependencyHijack\\b|\\bnamespaceHijack\\b', '(?i)\\b(?:pip|npm|gem|maven)\\b.{0,40}\\b(?:abandoned|unmaintained)\\b', '(?i)\\bhijackPackage\\b|\\btypoSquat\\b']},
    {'id': 'CALUS-MCP-SCAN-185', 'name': 'mcp-sampling-abuse-extraction', 'severity': 'low', 'category': 'mcp_security', 'message': 'Sampling abuse detected: MCP server is requesting LLM sampling to extract host context or influence other servers.', 'patterns': ['(?i)\\bsamplingAbuse\\b|\\bsamplingExtraction\\b', '(?i)\\bsampling\\s*request\\s*(?:with|for)\\s*(?:context|data)\\b']},
    {'id': 'CALUS-MCP-SCAN-186', 'name': 'mcp-tool-attestation-hash-mismatch', 'severity': 'medium', 'category': 'mcp_security', 'message': 'MCP tool attestation hash comparison detected: ensures tool definition integrity per Property 1.', 'patterns': ['(?i)tool_attestation_record\\(|TAR\\(', '(?i)H\\(def_current\\(t\\)\\)|def_current\\s*\\(\\s*t\\s*\\)', '(?i)hash_of_tool_definition|H\\(def\\(t\\)\\)']},
    {'id': 'CALUS-MCP-SCAN-187', 'name': 'mcp-capability-chaining-policy', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Capability chaining composition policy defined: restricts tool invocation sequences to prevent unauthorized outcomes.', 'patterns': ['(?i)composition_policy\\s*[=:]\\s*\\[|rho\\s*[=:]', '(?i)allow_after|deny_after|audit_after|tool_chain_policy']},
    {'id': 'CALUS-MCP-SCAN-188', 'name': 'mcp-sampling-abuse-bidirectional-channel', 'severity': 'medium', 'category': 'mcp_security', 'message': 'MCP sampling abuse: malicious server requests LLM sampling to exfiltrate context or influence behavior.', 'patterns': ['(?i)sampling/createMessage|sampling_create_message', '(?i)sampling_abuse|malicious_sampling']},
    {'id': 'CALUS-MCP-SCAN-190', 'name': 'mcp-memory-poisoning-persistent-context', 'severity': 'high', 'category': 'mcp_security', 'message': 'MCP memory poisoning: adversarial tool output injected into persistent memory, corrupting future agent reasoning.', 'patterns': ['(?i)memory\\.(?:add|update|append|store)\\s*\\(.{0,40}tool_output|persistent_context']},
    {'id': 'CALUS-MCP-SCAN-191', 'name': 'mcp-protocol-confusion-bridge', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP cross-protocol confusion: bridging MCP with A2A or other protocols creates exploitable semantic gaps.', 'patterns': ['(?i)(?:mcp.{0,40}a2a|a2a.{0,40}mcp)\\s*bridge|protocol_confusion', '(?i)cross_protocol_handler|multi_protocol_agent']},
    {'id': 'CALUS-MCP-SCAN-192', 'name': 'mcp-composition-policy-absence', 'severity': 'low', 'category': 'mcp_security', 'message': 'Absence of composition policies (sequential tool invocation restrictions). Attackers can chain individually benign tools to exfiltrate data or escalate privileges.', 'patterns': ['(?i)(?:class|struct|protocol)\\s+(?:MCP|Tool|Server).{0,100}\\b(?:invoke|call|execute)\\b.{0,100}\\btool\\b', '(?i)(?:def|function)\\s+\\w+.{0,100}\\b(?:chain|sequence|compose|combine)\\b.{0,100}\\btool']},
    {'id': 'CALUS-MCP-SCAN-193', 'name': 'mcp-tool-version-regression', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Tool version regression detected: rolling back to a previous version may reintroduce known vulnerabilities or alter tool behavior post-approval.', 'patterns': ['(?i)(?:def_current_version|rollback_to|versioned_tool)\\s*[=<].{0,20}\\b(?:1\\.0|0\\.9|older)\\b']},
    {'id': 'CALUS-MCP-SCAN-194', 'name': 'mcp-consent-bypass-auto-approve', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Auto-approval or consent bypass mechanism detected. Attackers can force tool invocations that should require explicit user confirmation, enabling unauthorized actions.', 'patterns': ['(?i)(?:def|function)\\s+\\w*.{0,40}(?:approve|confirm|consent).{0,80}\\b(?:tool|call|invoke)\\b']},
    {'id': 'CALUS-MCP-SCAN-195', 'name': 'mcp-rug-pull-capability-escalation', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP server code shows capability escalation pattern: incrementally expanding tool access across versions.', 'patterns': ['(?i)(?:capability|scope|permission|access_level)\\s*(?:\\+\\+|\\+=|append|extend)', '(?i)(?:capability|scope|permission)\\s*=\\s*[\'"](?:read|write|execute|admin)[\'"].{0,40}(?:capability|scope|permission)\\s*=\\s*[\'"](?:write|execute|admin)[\'"]', '(?i)\\bversion\\s*(?:increment|\\+=|\\+\\+).{0,40}\\btool\\b.{0,40}\\bcapability\\b']},
