    {'id': 'CALUS-MCP-SCAN-331', 'name': 'mcp-command-injection-explicit-shell-true', 'severity': 'critical', 'category': 'mcp_security', 'message': 'Explicit shell=True in subprocess call allows command injection if arguments contain LLM-controlled text.', 'patterns': ['child_process\\.exec(?:Sync)?\\s*\\(']},
    {'id': 'CALUS-MCP-SCAN-332', 'name': 'mcp-command-injection-unvalidated-llm-input', 'severity': 'high', 'category': 'mcp_security', 'message': 'LLM-generated input passed directly to subprocess without sanitization risks command injection.', 'patterns': ['subprocess\\.(?:run|Popen|call)\\s*\\(\\s*\\[?\\s*(?:f[\'"]|[\'"]\\s*\\+\\s*user_input|[\'"]\\s*\\.\\s*format)', 'child_process\\.exec(?:Sync)?\\s*\\(\\s*(?:f[\'"]|[\'"]\\s*\\+\\s*user_input)']},
    {'id': 'CALUS-MCP-SCAN-333', 'name': 'mcp-tool-poisoning-description-embedded-instructions', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool description contains imperative language that may bias LLM tool selection.', 'patterns': ["'description'\\s*:\\s*'[^']{0,200}\\b(?:always|must|should|recommend|prefer|first)\\b[^']{0,200}'"]},
    {'id': 'CALUS-MCP-SCAN-334', 'name': 'mcp-tool-shadowing-name-collision', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool name is a common verb that may cause shadowing or confusion with other tools.', 'patterns': ['"name"\\s*:\\s*"(?:read|write|delete|exec|run|list|get|set|create|update)\\b', "'name'\\s*:\\s*'(?:read|write|delete|exec|run|list|get|set|create|update)\\b"]},
    {'id': 'CALUS-MCP-SCAN-335', 'name': 'mcp-rug-pull-tool-description-post-deployment-change', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool description or schema may change post-deployment; verify against a cryptographic hash.', 'patterns': ['"description"\\s*:\\s*"[^"]{0,500}"\\s*,\\s*"inputSchema"']},
    {'id': 'CALUS-MCP-SCAN-336', 'name': 'mcp38-identity-spoofing-import', 'severity': 'critical', 'category': 'mcp_security', 'message': 'MCP identity spoofing tool: import of impersonation library or netcat reverse shell detected. Attackers register rogue MCP servers impersonating legitimate ones.', 'patterns': ['(?i)(?:from|import)\\s+(?:impersonate|malicious_mcp|rogue_server|spoof_mcp_server|mcp_spoof)\\b', '(?i)subprocess\\.(?:run|Popen|call)\\s*\\(\\s*\\[\\s*[\'"]nc[\'"]\\s*,\\s*[\'"]-lvp[\'"]', '(?i)subprocess\\.\\w+\\s*\\(\\s*[\'"][^\'"]*\\bnc\\s+-lvp\\b']},
    {'id': 'CALUS-MCP-SCAN-337', 'name': 'mcp38-credential-theft-env-read', 'severity': 'critical', 'category': 'mcp_security', 'message': 'MCP credential theft: code reads environment variables or config files containing secrets. Attackers exfiltrate API keys, tokens, and passwords.', 'patterns': ['(?i)open\\(\\s*[\'"](?:\\.env|config\\.json|credentials\\.(?:yml|yaml|json))[\'"]\\s*\\)', '(?i)subprocess\\.(?:run|Popen|call)\\s*\\(\\s*\\[\\s*[\'"]cat[\'"].{0,40}[\'"]\\.env[\'"]', '(?i)subprocess\\.\\w+\\s*\\(\\s*[\'"][^\'"]*\\bcat\\s+\\.env\\b']},
    {'id': 'CALUS-MCP-SCAN-338', 'name': 'mcp38-tool-description-poisoning', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP tool description poisoning: description or inputSchema.description contains imperative instructions that bias LLM tool selection. Attackers embed adversarial commands in manifest fields.', 'patterns': ['(?i)description[\'"]\\s*:\\s*[\'"][^\'"]{0,200}\\b(?:ignore|override|always|must|should|execute|run|call|use|select)\\b.{0,60}\\b(?:tool|function|api|command)\\b', '(?i)description[\'"]\\s*:\\s*[\'"][^\'"]{0,200}(?:\\bignore all previous instructions\\b|\\bif you see\\b|\\bwhen asked\\b|\\byou are now\\b|\\byou should not\\b)']},
    {'id': 'CALUS-MCP-SCAN-340', 'name': 'mcp38-rug-pull-mutable-manifest', 'severity': 'critical', 'category': 'mcp_security', 'message': 'MCP rug pull: tool manifest can be modified after deployment. Attackers change tool descriptions post-audit to inject malicious instructions.', 'patterns': ['(?i)(?:update_manifest|modify_description|set_tool_descriptor|change_tool|override_tool)\\b', '(?i)(?:tool_description|manifest)\\s*=\\s*[\\w]+\\s*\\(\\s*[\'"][^\'"]+[\'"]\\s*\\)']},
    {'id': 'CALUS-MCP-SCAN-341', 'name': 'mcp38-parasitic-toolchain-exfil', 'severity': 'critical', 'category': 'mcp_security', 'message': 'MCP parasitic toolchain: code that chains multiple tools to exfiltrate data. Attackers compose benign tools to create exfiltration paths.', 'patterns': ['(?i)subprocess\\.(?:run|Popen|call)\\s*\\(\\s*\\[\\s*[\'"]curl[\'"].{0,60}(?:POST|--data|-d|--header|-H)', '(?i)requests\\.(?:post|put|get)\\s*\\(\\s*[\'"](?:http|https)://[^\'"]*\\.(?:ngrok|attacker|evil|exfil)\\.\\w+']},
    {'id': 'CALUS-MCP-SCAN-342', 'name': 'mcp38-mitm-transport-tamper', 'severity': 'critical', 'category': 'mcp_security', 'message': 'MCP transport security bypass: TLS verification disabled, enabling man-in-the-middle attacks. Attackers can intercept and modify MCP messages.', 'patterns': ['(?i)(?:verify|ssl|tls|cert)_(?:false|False|none|None|no|off)\\s*(?:=|:\\s*)(?:False|0|None|\'off\'|"off")', '(?i)requests\\.(?:get|post)\\s*\\(.{0,40}verify\\s*=\\s*(?:False|0)', '(?i)urllib3\\.disable_warnings']},
    {'id': 'CALUS-MCP-SCAN-343', 'name': 'mcp38-command-injection-shell-tool', 'severity': 'critical', 'category': 'mcp_security', 'message': 'MCP command injection: LLM output passed unsanitized to shell execution. Confirmed by CVE-2025-6514 in mcp-remote.', 'patterns': ['(?i)subprocess\\.(?:run|Popen|call)\\s*\\(\\s*(?:f[\'"]|[\'"].{0,40}\\{).{0,100}\\bshell\\s*=\\s*True\\b', '(?i)os\\.system\\s*\\(\\s*(?:f[\'"]|[\'"].{0,40}\\{).{0,100}', '(?i)exec\\s*\\(\\s*(?:f[\'"]|[\'"].{0,40}\\{)']},
    {'id': 'CALUS-MCP-SCAN-344', 'name': 'mcp38-path-traversal-file-tool', 'severity': 'critical', 'category': 'mcp_security', 'message': 'MCP path traversal: file tool does not canonicalize paths, allowing directory escape. Attackers access files outside the intended sandbox.', 'patterns': ['(?i)(?:read_file|write_file|read|write|open|file_read|file_write)\\s*\\(.{0,40}\\bpath\\b\\s*[=:]\\s*[\'"].{0,40}(?:\\/\\.\\.|\\..\\/|%2e%2e)', '(?i)Path\\(user_input\\)']},
    {'id': 'CALUS-MCP-SCAN-345', 'name': 'mcp38-supply-chain-malicious-import', 'severity': 'medium', 'category': 'mcp_security', 'message': 'MCP supply chain compromise: import of suspicious or known malicious MCP package. Attackers inject malicious code in public registries.', 'patterns': ['(?i)(?:from|import)\\s+(?:mcp_malicious|evil_mcp|rogue_mcp|malicious_mcp_server)\\b', '(?i)pip\\s+install\\s+[\\w-]*\\b(?:malicious|evil|rogue|dangerous|hack)\\b[\\w-]*']},
    {'id': 'CALUS-MCP-SCAN-346', 'name': 'mcp38-stdio-descriptor-misuse', 'severity': 'high', 'category': 'mcp_security', 'message': 'MCP stdio descriptor misuse: file descriptors used for stdio transport are exposed to unauthorized processes. Attackers can inject messages into the MCP stream.', 'patterns': ['(?i)os\\.(?:dup|dup2|pipe|open)\\s*\\(.{0,40}\\b(?:stdin|stdout|stderr|STDIN_FILENO|STDOUT_FILENO|STDERR_FILENO)\\b']},
    {'id': 'CALUS-MCP-SCAN-347', 'name': 'mcp38-unrestricted-network-access', 'severity': 'high', 'category': 'mcp_security', 'message': 'MCP unrestricted network access: tool can reach internal/private network targets, enabling lateral movement. 33% of MCP tools allow this per Docker.', 'patterns': ['(?i)socket\\.(?:connect|create_connection)\\s*\\(\\s*\\(\\s*[\'"](?:10\\.|172\\.|192\\.168\\.|localhost|127\\.0\\.0\\.1)']},
    {'id': 'CALUS-MCP-SCAN-348', 'name': 'mcp38-sandbox-escape-docker-escape', 'severity': 'critical', 'category': 'mcp_security', 'message': 'MCP sandbox escape: code attempts to break out of container/sandbox. Confirmed by CVE-2025-6514 and Docker MCP Security.', 'patterns': ['(?i)/proc/1/root/', '(?i)\\.containerenv', '(?i)os\\.system\\s*\\(\\s*[\'"]mkdir -p /tmp/escape && mount -o bind', '(?i)subprocess\\.(?:run|Popen|call)\\s*\\(\\s*\\[\\s*[\'"]nsenter[\'"]', '(?i)subprocess\\.\\w+\\s*\\(\\s*[\'"][^\'"]*\\bnsenter\\b']},
    {'id': 'CALUS-MCP-SCAN-349', 'name': 'mcp38-dos-unbounded-llm-calls', 'severity': 'medium', 'category': 'mcp_security', 'message': 'MCP resource exhaustion: code can trigger unbounded LLM calls or API requests, leading to denial of wallet or service degradation.', 'patterns': ['(?i)(?:while|for)\\s+(?:True|1)\\s*:.{0,40}\\b(?:llm|api|tool|request)\\.(?:call|invoke|generate|complete)\\b', '(?i)recursive\\s*(?:call|invoke|prompt|tool)\\s*\\(', '(?i)def\\s+loop_tool\\s*\\(.{0,40}\\):']},
    {'id': 'CALUS-MCP-SCAN-350', 'name': 'mcp-38-dynamic-rug-pull-manifest', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected runtime modification of MCP tool manifest fields, indicating potential rug-pull attack where tool behavior changes post-registration.', 'patterns': ['(?i)(?:tool_manifest|tool_list|tool_registry)\\.{0,40}(?:update|modify|overwrite|patch|replace)', '(?i)(?:set_tool|register_tool|update_tool_description|modify_tool_schema)']},
    {'id': 'CALUS-MCP-SCAN-351', 'name': 'mcp-38-resource-content-poisoning', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected resource content poison injection pattern that embeds adversarial instructions in external data consumed by MCP tools.', 'patterns': ['(?i)(?:resource_content|resource_list|read_resource)\\.{0,40}(?:inject|poison|taint|contaminate)']},
