    {'id': 'CALUS-MCP-SCAN-353', 'name': 'mcp-38-parasitic-tool-chain-exfil', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected parasitic tool chaining pattern that composes multiple tools into an exfiltration path, bypassing per-tool controls.', 'patterns': ['(?i)(?:chain|compose|sequence|pipeline)\\s+tool.{0,40}(?:exfil|send|write|transfer)', '(?i)(?:tool_chain|tool_pipeline|multi_tool).{0,40}(?:output|result|content).{0,40}(?:http|email|socket|file)']},
