    {'id': 'CALUS-MCP-SCAN-357', 'name': 'mcp-38-endpoint-rebinding-attack', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected DNS rebinding or endpoint manipulation pattern targeting MCP servers.', 'patterns': ['(?i)(?:dns_rebind|rebind|dns_poison|domain_switch).{0,40}(?:mcp|server|endpoint)', '(?i)(?:resolve|lookup|connect_to).{0,40}(?:attacker_controlled|malicious_domain|rebind_payload)']},
    {'id': 'CALUS-MCP-SCAN-358', 'name': 'mcp-38-privacy-inversion-aggregation', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected privacy inversion pattern that aggregates tool outputs to reconstruct sensitive information.', 'patterns': ['(?i)(?:aggregate|combine|merge|cross_reference).{0,40}(?:privacy|sensitive|PII|location|schedule)', '(?i)(?:privacy_inversion|composite_leak|inference_attack).{0,40}(?:tool|data|record)']},
    {'id': 'CALUS-MCP-SCAN-359', 'name': 'mcp-38-resource-exhaustion-loop', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected resource exhaustion or denial-of-wallet pattern using unbounded tool chaining loops.', 'patterns': ['(?i)(?:loop|recursive|cyclic|infinite).{0,40}(?:tool|call|invoke|chain).{0,40}(?:exhaust|denial|overload)']},
