    {'id': 'CALUS-MCP-SCAN-361', 'name': 'mcp-38-multi-agent-context-poisoning', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected multi-agent context poisoning pattern where a compromised agent modifies shared state to influence other agents.', 'patterns': ['(?i)(?:shared_context|global_state|agent_comm).{0,40}(?:poison|inject|taint|corrupt)', '(?i)(?:multi_agent|inter_agent).{0,40}(?:context|state|message).{0,40}(?:modify|override|inject)']},
    {'id': 'CALUS-MCP-SCAN-362', 'name': 'mcp-38-invisible-activity-no-logging', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected log suppression or disabling of audit trail for MCP operations, enabling invisible agent activity.', 'patterns': ['(?i)(?:disable_log|no_audit|suppress_audit|skip_logging).{0,40}(?:mcp|tool|call|request)', '(?i)(?:audit_disabled|logging_off|no_trace|invisible).{0,40}(?:agent|mcp|operation)']},
