    {'id': 'CALUS-MCP-SCAN-364', 'name': 'mcp-38-consent-fatigue-masquerade', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected consent fatigue or consent masquerading pattern that exploits frequent approval requests.', 'patterns': ['(?i)(?:consent_fatigue|approval_fatigue|masquerade_consent|bait_and_switch).{0,40}(?:request|approve|allow)', '(?i)(?:bulk_consent|rapid_approval|automated_confirm).{0,40}(?:dangerous|critical|admin)']},
    {'id': 'CALUS-MCP-SCAN-365', 'name': 'mcp-insecure-stdio-descriptor-handling', 'severity': 'low', 'category': 'mcp_security', 'message': 'Insecure stdio descriptor handling detected: potential for MCP message stream injection or eavesdropping.', 'patterns': ['(?i)(?:dup2|dup)\\s*\\(\\s*(?:STDIN_FILENO|STDOUT_FILENO|0|1|2)', '(?i)exec\\s*\\(\\s*["\'].{0,40}?mcp', '(?i)(?:spawn|fork|exec).{0,40}(?:mcp|jsonrpc).{0,40}(?:stdio|pipe)', '(?i)close\\s*\\(\\s*(?:0|1|2)\\s*\\)']},
    {'id': 'CALUS-MCP-SCAN-366', 'name': 'mcp-endpoint-dns-rebinding', 'severity': 'medium', 'category': 'mcp_security', 'message': 'DNS rebinding code detected: potential for MCP endpoint hijacking.', 'patterns': ['(?i)dns_rebind|dnsrebind|rebinding.{0,20}dns', '(?i)evilhelper|rebinder', '(?i)(?:import|from)\\s+.{0,40}dns.{0,40}rebind']},
    {'id': 'CALUS-MCP-SCAN-367', 'name': 'mcp-preference-manipulation-metadata', 'severity': 'low', 'category': 'mcp_security', 'message': 'Preference manipulation metadata detected: potential bias injection for LLM tool selection.', 'patterns': ['(?i)"priority"\\s*:\\s*(?:1|2|3).{0,40}"description"', '(?i)"recommended"\\s*:\\s*true', '(?i)"popularity"\\s*:\\s*[0-9]{3,}', '(?i)(?:annotations|metadata).{0,60}(?:priority|recommended|popular|favorite)']},
    {'id': 'CALUS-MCP-SCAN-368', 'name': 'mcp-consent-fatigue-generator', 'severity': 'low', 'category': 'mcp_security', 'message': 'Consent fatigue attack code detected: automated approval dialogs may condition users to approve dangerous operations.', 'patterns': ['(?i)consent.{0,40}(?:fatigue|spam|schedule|timer)']},
    {'id': 'CALUS-MCP-SCAN-369', 'name': 'mcp-missing-integrity-verification', 'severity': 'high', 'category': 'mcp_security', 'message': 'Mutable tool manifest: no cryptographic integrity verification - descriptions can be silently modified post-deployment.', 'patterns': ['(?i)tool\\.describe|customize_tool|modify_tool|update_description', '(?i)tool_manifest\\s*=\\s*\\{.{0,40}"description":', '(?i)manifest\\.(?:description|schema)\\s*=', '(?i)(?:set|update|change)_(?:tool|resource|prompt)_(?:description|metadata)']},
    {'id': 'CALUS-MCP-SCAN-370', 'name': 'mcp-multi-agent-context-hijacking', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Multi-agent context hijacking detected: compromised agent can poison downstream agent reasoning.', 'patterns': ['(?i)agent_communication.{0,40}(?:inject|poison|compromise|hijack)', '(?i)shared_context.{0,40}(?:append|add|merge|concat).{0,40}(?:instruction|payload|malicious)', '(?i)context_bus|event_bus|message_queue.{0,60}(?:inject|poison|compromise)', '(?i)downstream_agent|next_agent.{0,40}(?:instruction|context|payload)']},
    {'id': 'CALUS-MCP-SCAN-371', 'name': 'mcp-privacy-inversion-aggregator', 'severity': 'low', 'category': 'mcp_security', 'message': 'Potential privacy inversion: code that aggregates multiple data sources to reconstruct sensitive information.', 'patterns': ['(?i)combine.{0,40}(?:results|outputs|fields|data).{0,40}(?:name|email|phone|address)', '(?i)aggregate.{0,40}(?:user|profile|personal|private|sensitive)', '(?i)(?:join|merge|union).{0,40}(?:data|table|collection).{0,40}(?:name|email|phone|address)']},
    {'id': 'CALUS-MCP-SCAN-372', 'name': 'mcp-invisible-activity-no-audit', 'severity': 'low', 'category': 'mcp_security', 'message': 'Missing audit logging: no trace generated for agent activity - attacks may go unnoticed.', 'patterns': ['(?i)(?:audit|log)\\.(?:disable|suppress|silence|mute|deactivate)', '(?i)logging\\.(?:basicConfig|disable)\\(.{0,40}(?:False|critical|error)', '(?i)no_log|nosyslog|quiet_mode|silent_mode', '(?i)(?:import|from)\\s+.{0,40}logging.{0,40}\\..{0,40}(?:disable|suppress)']},
    {'id': 'CALUS-MCP-SCAN-373', 'name': 'mcp-mitm-transport-tampering', 'severity': 'high', 'category': 'mcp_security', 'message': 'Detected TLS certificate verification disabled in MCP transport code; allows MITM attack (MCP-28).', 'patterns': ['(?i)requests\\.(?:get|post|put|delete)\\s*\\(\\s*[\'"](?:https?:)?//[^\'"]+\\s*,\\s*(?:verify|check)\\s*=\\s*False', '(?i)urllib\\.request\\.urlopen\\([^)]*(?:context\\s*=\\s*ssl\\._unverifiable|verify\\s*=\\s*False)', '(?i)ssl\\._create_default_https_context\\s*=\\s*ssl\\._create_unverified_context']},
    {'id': 'CALUS-MCP-SCAN-374', 'name': 'mcp-insecure-stdio-descriptor', 'severity': 'high', 'category': 'mcp_security', 'message': 'Detected insecure stdio descriptor handling in MCP server; may allow message stream injection (MCP-30).', 'patterns': ['(?i)(?:subprocess\\.(?:Popen|run|call)\\s*\\(\\s*(?:\\[\\s*[\'"]|[\'"]))[^\'"]*(?:mcp|stdio|--stdio|--transport\\s+stdio)', '(?i)os\\.dup2\\(\\s*(?:0|1|2)\\s*,\\s*(?:fd|newfd)', '(?i)pty\\.spawn\\s*\\(\\s*(?:\\[\\s*[\'"]|[\'"])\\S*(?:mcp|stdio)']},
    {'id': 'CALUS-MCP-SCAN-375', 'name': 'mcp-ssrf-via-http-proxy', 'severity': 'critical', 'category': 'mcp_security', 'message': 'MCP HTTP proxy tool allows requests to internal or metadata endpoints; SSRF risk (MCP-09).', 'patterns': ['(?i)aiohttp\\.ClientSession\\.get\\s*\\(\\s*[\'"].{0,40}\\{\\s*url\\s*\\}', '(?i)(?:urllib\\.request\\.urlopen|httpx\\.get|requests\\.get)\\s*\\(\\s*(?:user_url|target_url|url_to_fetch)']},
    {'id': 'CALUS-MCP-SCAN-376', 'name': 'mcp-command-injection-via-tool-output', 'severity': 'critical', 'category': 'mcp_security', 'message': 'Detected shell invocation with dynamic content from LLM output; risk of command injection (MCP-07).', 'patterns': ['(?i)(?:subprocess\\.(?:run|Popen|call)\\s*\\(\\s*[\'"][^\'"]*\\{\\s*.{0,40}\\s*\\}|subprocess\\.(?:run|Popen|call)\\s*\\(\\s*[\'"].{0,40}\\+\\s*\\w+\\s*[^)]*shell\\s*=\\s*True)', '(?i)os\\.system\\s*\\(\\s*(?:f[\'"]|[\'"].{0,40}\\{.{0,40}\\}|[\'"].{0,40}\\%\\s*s\\s*\\%\\s*\\w+)', '(?i)subprocess\\.check_output\\s*\\(\\s*[\'"].{0,40}\\+\\s*\\w+\\s*,\\s*shell\\s*=\\s*True']},
    {'id': 'CALUS-MCP-SCAN-377', 'name': 'mcp-insecure-stdio-descriptor-handling', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected insecure stdio descriptor handling pattern in MCP server code.', 'patterns': ['(?i)(?:from|import)\\s+os\\.(?:fdopen|pipe|dup)', '(?i)os\\.(?:fdopen|pipe|dup)\\s*\\(\\s*\\d+', '(?i)(?:dup2|dup)\\s*\\(\\s*\\d+,\\s*\\d+', '(?i)\\bfcntl\\.FD_CLOEXEC\\b']},
    {'id': 'CALUS-MCP-SCAN-378', 'name': 'mcp-manifest-resource-uri-injection', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected potentially malicious URI pattern in MCP resource manifest.', 'patterns': ['(?i)"uri"\\s*:\\s*"file:///', '(?i)"uri"\\s*:\\s*"(http|https)://.{0,40}@', '(?i)"uri"\\s*:\\s*"gopher://', '(?i)resourceUri\\s*=\\s*[\'"](file|gopher|dict)://']},
