    {'id': 'CALUS-MCP-SCAN-430', 'name': 'mcp-insecure-stdio-fd-handling', 'severity': 'low', 'category': 'mcp_security', 'message': 'Direct file descriptor duplication (dup2) detected in MCP stdio transport handlers. Improper management can allow uncontrolled fd injection (MCP-30).', 'patterns': ['(?i)dup2\\s*\\(\\s*\\d+\\s*,\\s*\\d+\\s*\\)', '(?i)(os\\.)?dup2\\s*\\(\\s*fd\\s*,\\s*\\d+\\s*\\)', '(?i)\\.dup2\\s*\\(\\s*std(in|out|err)\\s*,\\s*\\d+\\s*\\)']},
    {'id': 'CALUS-MCP-SCAN-431', 'name': 'mcp-consent-fatigue-parasitic-prompt', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected configuration that reduces consent prompts or enables batch approval, enabling consent fatigue attacks (MCP-23).', 'patterns': ['(?i)consent\\s*(?:request|prompt)\\s*interval\\s*[=:]<\\d+', '(?i)batch_approve\\s*[=:].{0,40}\\btrue\\b', '(?i)(suppress_consent|skip_approval)\\s*[=:].{0,40}\\btrue\\b']},
    {'id': 'CALUS-MCP-SCAN-432', 'name': 'mcp-38-credential-tool-patterns', 'severity': 'high', 'category': 'mcp_security', 'message': 'Tool code references printenv or os.environ, which can expose secrets.', 'patterns': ['(?i)(?:from|import)\\s+printenv\\b', '(?i)subprocess\\.(?:run|Popen|call)\\s*\\(\\s*\\[\\s*[\'"]printenv[\'"]', '(?i)subprocess\\.\\w+\\s*\\(\\s*[\'"][^\'"]*\\bprintenv\\b']},
    {'id': 'CALUS-MCP-SCAN-433', 'name': 'mcp-38-config-read-tool', 'severity': 'high', 'category': 'mcp_security', 'message': 'Tool reads .env file, potential credential exfiltration.', 'patterns': ['(?i)(?:read|open|cat)\\s*\\(\\s*[\'"].{0,40}\\.env\\b', '(?i)subprocess\\.(?:run|Popen|call)\\s*\\(\\s*\\[\\s*[\'"]cat[\'"]\\s*,\\s*[\'"]\\.env[\'"]', '(?i)pathlib\\.Path\\(\\s*[\'"].{0,40}\\.env\\b']},
    {'id': 'CALUS-MCP-SCAN-435', 'name': 'mcp-38-input-schema-description-poisoning', 'severity': 'low', 'category': 'mcp_security', 'message': 'inputSchema description contains instruction-override phrase.', 'patterns': ['(?i)\\bignore\\s+the\\s+(?:previous|above)\\s+instructions\\b', '(?i)\\bwhen\\s+you\\s+see\\b.{0,40}\\bignore\\b']},
    {'id': 'CALUS-MCP-SCAN-436', 'name': 'mcp-38-tool-shadowing-name-collision', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool name suspiciously similar to common tools; potential shadowing.', 'patterns': ['(?i)\\bname\\s*[:=]\\s*[\'"]read_file[\'"]']},
    {'id': 'CALUS-MCP-SCAN-437', 'name': 'mcp-38-preference-manipulation-metadata', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool description contains promotional language that may bias LLM selection.', 'patterns': ['(?i)\\bpopular\\b.{0,40}\\b(?:tool|method|approach)\\b']},
    {'id': 'CALUS-MCP-SCAN-438', 'name': 'mcp-38-rogue-server-registration', 'severity': 'low', 'category': 'mcp_security', 'message': "Server registered with 'local' type or impersonating well-known service name.", 'patterns': ['(?i)\\bname\\s*[:=]\\s*[\'"](?:github|gitlab|google|aws|azure|docker)[-_]?mcp[-_]?server[\'"]']},
    {'id': 'CALUS-MCP-SCAN-439', 'name': 'mcp-credential-theft-printenv-tool', 'severity': 'high', 'category': 'mcp_security', 'message': "MCP tool 'printEnv' or similar environment-reading tool detected. This can be used to exfiltrate credentials from environment variables.", 'patterns': ['(?i)(?:def|class)\\s+.{0,40}(?:printEnv|print_env|getenv|read_env)\\s*\\(', '(?i)(?:tools\\.(?:add|create|register)|@tool)\\s*\\([^)]*(?:name=[\'"]?(?:printEnv|print_env|getenv|read_env)[\\"\']?)', '(?i)(?:description\\s*[:=]\\s*[\'"].{0,100}print.{0,100}environment)']},
