    {'id': 'CALUS-MCP-SCAN-441', 'name': 'mcp-path-traversal-file-tool', 'severity': 'high', 'category': 'mcp_security', 'message': 'MCP file tool may be vulnerable to path traversal. Use canonicalized paths and restrict access to allowed directory.', 'patterns': ['(?i)open\\(\\s*[\\"\'`].{0,40}[\\"\'`]\\s*[+%].{0,40}path', '(?i)(?:os\\.path\\.join|Path\\(|open\\()\\s*[^)]*\\broot_dir\\b[^)]*[+%]']},
    {'id': 'CALUS-MCP-SCAN-442', 'name': 'mcp-full-schema-poisoning-inputschema', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Potential full schema poisoning: inputSchema description field contains suspicious instructions that may mislead LLM.', 'patterns': ['(?i)inputSchema\\s*[=:].{0,100}description.{0,50}(?:ignore|instruct|perform|execute|bypass|jailbreak)']},
    {'id': 'CALUS-MCP-SCAN-443', 'name': 'mcp-tool-shadowing-similar-name', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP tool name closely resembles a trusted service (e.g., google-drive-connector). Verify ownership.', 'patterns': ['(?i)(?:[\'"]name[\'"])\\s*[:=]\\s*[\'"](?:g(?:oogle|ithub|mail|drive|slack|aws|azure|gcp|dropbox|notion)[-_]{2,}|[\'"]g(?:oogle|ithub|mail|drive|slack|aws|azure|gcp|dropbox|notion)[-_]?[a-z]{0,3}[0-9]{2,}[\'"])']},
    {'id': 'CALUS-MCP-SCAN-444', 'name': 'mcp-integrity-verification-missing-cryptographic-signature', 'severity': 'critical', 'category': 'mcp_security', 'message': 'MCP server manifest or tool registration missing cryptographic signature enables rug-pull and tampering attacks. MCP-38 MCP-27.', 'patterns': ['(?i)(?:from|import)\\s+mcp_integrity\\b', '(?i)\\.(?:verify|check|validate)_(?:signature|hash|integrity)\\s*\\([^)]*tool[^)]*\\)', '(?i)content_?(?:address|hash)\\s*[=:].{0,40}[a-f0-9]{64}', '(?i)manifest_signature\\s*[=:]\\s*[\'"][^\'"]{10,}[\'"]']},
    {'id': 'CALUS-MCP-SCAN-445', 'name': 'mcp-oauth-token-missing-state-parameter', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP OAuth flow omits or improperly validates the state parameter, enabling CSRF and authorization code interception. MCP-38 MCP-03.', 'patterns': ['(?i)authorization_endpoint\\s*[=:].{0,40}oauth', '(?i)oauth\\s*(?:flow|config|handler).{0,60}state.{0,40}(?:omit|skip|none|missing)', '(?i)(?:client_id|redirect_uri)\\s*[=:].{0,100}authorization_endpoint']},
