    {'id': 'CALUS-MCP-SCAN-447', 'name': 'mcp-insecure-descriptor-handling-stdio-file-descriptor-leak', 'severity': 'low', 'category': 'mcp_security', 'message': 'Insecure stdio descriptor handling detected; may allow process injection or message stream interception. MCP-38 MCP-30.', 'patterns': ['(?i)(?:dup2|dup|pipe|open).{0,40}(?:0|1|2|STDIN|STDOUT|STDERR).{0,60}(?:stdio|transport|mcp)', '(?i)transport.{0,40}(?:stdio|pipe).{0,60}(?:inject|read|write|intercept)']},
    {'id': 'CALUS-MCP-SCAN-448', 'name': 'mcp-unrestricted-network-access-lateral-movement-tool', 'severity': 'medium', 'category': 'mcp_security', 'message': 'MCP tool allows unrestricted network access, enabling lateral movement from compromised servers. MCP-38 MCP-32.', 'patterns': ['(?i)allow_private_ips\\s*[=:]\\s*true\\b', '(?i)(?:internal|private)_(?:network|ip|address).{0,40}(?:access|allow|permit|enable)']},
