    {'id': 'CALUS-MCP-SCAN-491', 'name': 'dependency-confusion-mcp-package', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP package dependency name resembles popular package - possible dependency confusion.', 'patterns': ['"mcp-server-?[a-z]+" vs "mcp-server-[a-z]+" similarity', 'dependencies":\\s*\\{[^}]{0,500}"mcp-server-[a-z]+"\\s*:', '"name": "@scope/mcp-server-[a-z]+"']},
