    {'id': 'CALUS-MCP-SCAN-590', 'name': 'mcp-rug-pull-post-deploy-manifest-change', 'severity': 'high', 'category': 'mcp_security', 'message': 'Tool manifest fetched from remote URL without integrity verification. Attackers could replace tool descriptions silently after initial audit.', 'patterns': ['(?i)(?:fetch|get|load)ToolManifest\\s*\\(\\s*[\'"][^\'"]+[\'"]\\s*\\)', '(?i)(?:loadManifest|getToolList)\\s*\\(\\s*[\'"][^\'"]+[\'"]\\s*\\)']},
