    {'id': 'CALUS-MCP-SCAN-593', 'name': 'mcp-preference-manipulation-statistical', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool metadata contains priority or recommendation fields that may bias LLM tool selection, enabling Preference Manipulation Attack (MPMA).', 'patterns': ['(?i)metadata\\s*:\\s*\\{[^\\}]{0,500}(?:priority|recommended|popular|preferred)\\s*[:=]']},
