    {'id': 'CALUS-MCP-SCAN-596', 'name': 'mcp-multi-agent-context-hijacking-shared', 'severity': 'high', 'category': 'mcp_security', 'message': 'Potential multi-agent context hijacking: agent writes to shared context/memory, which could poison downstream agent reasoning.', 'patterns': ['(?i)(?:setContext|updateContext|writeContext|appendContext|storeInMemory|saveToSession)\\s*\\(\\s*[\'"][^\'"]+[\'"]\\s*,\\s*[\'"][^\'"]+[\'"]\\s*\\)', '(?i)(?:context|memory|session)\\s*\\.\\s*(?:set|update|append|write|push)\\s*\\(\\s*[\'"][^\'"]+[\'"]\\s*,\\s*[\'"][^\'"]+[\'"]\\s*\\)', '(?i)(?:from|import)\\s+(?:mcp-context|mcp-memory|shared-context)']},
