    {'id': 'CALUS-MCP-SCAN-744', 'name': 'mcp-38-credential-theft-env-exposure', 'severity': 'high', 'category': 'mcp_security', 'message': 'Credential Theft via Environment Exposure detected: code reads environment variables or sensitive config files and transmits them to external endpoints, enabling credential exfiltration.', 'patterns': ['(?i)(?:read_file|readFile|load_config|open_config).{0,60}(?:\\.env\x08|config\\.json|credentials\\.yml|secrets\\.tf|token\\.txt)', '(?i)(?:subprocess|exec|run|spawn).{0,40}(?:printenv|env|echo\\s+\\$).{0,40}(?:api|aws|secret|token|key|password)']},
