    {'id': 'CALUS-MCP-SCAN-800', 'name': 'mcp-38-tool-shadowing-name-collision', 'severity': 'low', 'category': 'mcp_security', 'message': 'Potential tool shadowing due to similar/squatted name near trusted service name.', 'patterns': ['(?i)\\b(?:name|tool|function|action)\\s*[=:]\\s*[\'"](?:[^\'"]{0,10})?[_-]?(?:connector|integration|reader|writer|fetcher|sync)[_-]?[^\'"\\s]{0,20}[\'"]', '(?i)\\b[\'"][A-Za-z]+_[A-Za-z]+[-_][A-Za-z]+[\'"]\\s*[=:]', '(?i)\\b(?:tool|function|action)\\s*[=:]\\s*[\'"](?:github|google|aws|azure|slack|notion|jira|confluence)[_-][^\'"\\s]{0,30}[\'"]']},
    {'id': 'CALUS-MCP-SCAN-801', 'name': 'mcp-38-oauth-state-parameter-omission', 'severity': 'low', 'category': 'mcp_security', 'message': "OAuth 'state' parameter is missing or improperly validated, enabling CSRF and authorization code replay.", 'patterns': ['(?i)\\bauthorize\\s*\\([^)]{0,200}\\bstate\\b[^)]{0,300}\\bstate\\s*=\\s*(?:[\'"][^\'"]*[\'"]|\\w+)', '(?i)\\b(?:oauth|oauth2)\\s*(?:callback|redirect|handler|flow)\\s*\\([^)]{0,200}(?:state|nonce)\\s*[=:]\\s*(?:[\'"][\'"]|null|undefined|None|False|0)']},
