    {'id': 'CALUS-MCP-SCAN-965', 'name': 'mcp-tool-selection-unsafe-plan', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected agent tool plan referencing a dangerous or admin-only tool that violates policy.', 'patterns': ['(?i)\\b(?:tool|action|plan)\\s*[:=]\\s*\\[?\\s*[\'"]\\s*(?:delete_user|drop_database|shutdown_node|format_disk)\\b', '(?i)"(?:tool|function)"\\s*:\\s*"(?:delete_user|drop_database|shutdown_node|format_disk)"', '(?i)(?:\'tool_name\'|\'name\')\\s*:\\s*[\'"]?(?:delete_user|drop_database|shutdown_node|format_disk)[\'"]?']},
    {'id': 'CALUS-MCP-SCAN-966', 'name': 'mcp-command-injection-run-script', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected run_script call with path traversal or shell metacharacters in filename parameter.', 'patterns': ['(?i)run_script\\s*\\(\\s*filename\\s*=\\s*[\'"]\\s*[\\.\\/]+']},
    {'id': 'CALUS-MCP-SCAN-967', 'name': 'mcp-tool-poisoning-masquerade-detection', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected tool registration mimicking a data visualization tool but sourcing from an external URL (possible masquerade).', 'patterns': ['(?i)"name"\\s*:\\s*"(?:data_viz|chart|visualization|plot)\\d*"[\\s\\S]{0,80}"url"\\s*:\\s*"(?:http|ftp|file)', '(?i)(?:register_tool|add_tool)\\s*\\([^)]*"name"\\s*:\\s*"(?:data_viz|chart|visualization|plot)\\d*"', '(?i)tool\\s*=\\s*\\{[^}]*"name"\\s*:\\s*"(?:data_viz|chart|visualization|plot)\\d*"[^}]*"source"\\s*:\\s*"(?:http|ftp|file)']},
    {'id': 'CALUS-MCP-SCAN-968', 'name': 'mcp-context-manipulation-emergency-bypass', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected prompt fabricating an emergency to coerce destructive infrastructure actions.', 'patterns': ['(?i)\\b(?:emergency|urgent|critical|disaster)\\b.{0,60}\\b(?:deprovision|delete|shutdown|remove|format|purge)\\b', '(?i)\\b(?:fake|simulated|pretend)\\s+(?:emergency|incident|critical).{0,40}\\b(?:deprovision|delete|shutdown|remove)\\b', '(?i)\\b(?:this is an emergency|urgent action required).{0,100}\\b(?:destroy|deallocate|erase|wipe)\\b']},
    {'id': 'CALUS-MCP-SCAN-969', 'name': 'mcp-bulk-deletion-outside-window', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected bulk deletion request that may violate time-based policies (e.g., permitted only on weekends).', 'patterns': ['(?i)"action"\\s*:\\s*"(?:delete|remove|purge|deprovision)"[\\s\\S]{0,60}"scope"\\s*:\\s*"(?:bulk|all|many|large)"', '(?i)(?:"query"|"command")[^}]*\\b(?:delete|remove|purge|deprovision)\\b[^}]*\\b(?:all|bulk|many|every)\\b']},
    {'id': 'CALUS-MCP-SCAN-970', 'name': 'unvalidated-action-proposal-scan', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Action proposal detected without mandatory consensus validation loop; may enable unauthorized tool execution.', 'patterns': ['(?i)(?:from\\s+.{0,40}import|import\\s+).{0,40}\\baction_proposal\\b', '(?i)def\\s+(?:propose_action|request_execution)\\b', '(?i)action_proposal\\s*=\\s*\\{']},
    {'id': 'CALUS-MCP-SCAN-971', 'name': 'shared-memory-poisoning-patterns', 'severity': 'low', 'category': 'mcp_security', 'message': 'Shared memory write detected without integrity filtering; vulnerable to poisoning and persistent error propagation.', 'patterns': ['(?i)(?:from|import)\\s+shared_memory\\s*(?:,\\s*|$)', '(?i)\\bshared_memory\\b.{0,40}\\.(?:update|write|store)\\(', '(?i)\\bmemory_pool\\s*\\[.{0,40}\\]\\s*=\\s*']},
    {'id': 'CALUS-MCP-SCAN-972', 'name': 'overprivileged-tool-scope', 'severity': 'high', 'category': 'mcp_security', 'message': 'Agent tool list includes overly broad capabilities; may lead to excessive agency and unauthorized actions.', 'patterns': ['(?i)\\btool_list\\s*=\\s*\\[.{0,40}\\]\\s*#\\s*all\\s+tools', '(?i)\\ballowed_tools\\s*=\\s*\\[.{0,40}\\].{0,40},\\s*(?:iam|admin|firewall)', '(?i)\\bcapabilities\\s*=\\s*\\[.{0,40}\\]\\s*#\\s*grant\\s+all']},
    {'id': 'CALUS-MCP-SCAN-973', 'name': 'unauthorized-validator-bypass', 'severity': 'low', 'category': 'mcp_security', 'message': 'Validator bypass detected; action can execute without authorization, leading to unauthorized execution or trust boundary violation.', 'patterns': ['(?i)\\bskip_validator\\s*=\\s*True', '(?i)#\\s*bypass\\s+validator', '(?i)\\bvalidator\\.bypass\\s*=']},
    {'id': 'CALUS-MCP-SCAN-974', 'name': 'flat-memory-access-patterns', 'severity': 'low', 'category': 'mcp_security', 'message': 'Flat shared memory structure detected; enables unauthorized cross-agent retrieval and lateral knowledge propagation.', 'patterns': ['(?i)\\bshared_memory\\s*=\\s*\\{', '(?i)\\bmemory\\s*=\\s*{}\\s*#\\s*global', '(?i)\\bglobal_memory\\s*=\\s*(?:dict|{}|\\[\\])']},
    {'id': 'CALUS-MCP-SCAN-975', 'name': 'unsigned-manifest-scanner', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool manifest or catalog defined without cryptographic signature; vulnerable to tool impersonation and hijacking.', 'patterns': ['(?i)\\btool_manifest\\s*=.{0,40}\\{\\s*["\']name["\']\\s*:', '(?i)\\badmin_catalog\\s*=\\s*\\[.{0,40}\\]', '(?i)\\btool_registry\\s*=\\s*\\[']},
    {'id': 'CALUS-MCP-SCAN-976', 'name': 'persistent-memory-dump', 'severity': 'low', 'category': 'mcp_security', 'message': 'Memory contents are being dumped to external sink; risk of privacy leakage and data poisoning.', 'patterns': ['(?i)\\bmemory\\.(?:dump|export|save|write)\\b.{0,40}\\.?\\b(?:log|file|csv|json)', '(?i)\\bjson\\.dumps?\\(.{0,40}memory\\b', '(?i)\\bwrite_memory_log\\s*\\(\\s*[\'"]memory']},
    {'id': 'CALUS-MCP-SCAN-977', 'name': 'blockchain-ledger-bypass', 'severity': 'low', 'category': 'mcp_security', 'message': 'Blockchain-anchored action commitment disabled; actions become non-repudiable only via logs, losing tamper-proof integrity.', 'patterns': ['(?i)#\\s*blockchain\\s*disabled', '(?i)\\bblockchain_commit\\s*=\\s*False', '(?i)\\buse_blockchain\\s*=\\s*False']},
    {'id': 'CALUS-MCP-SCAN-978', 'name': 'prompt-flow-integrity-bypass', 'severity': 'low', 'category': 'mcp_security', 'message': 'Prompt Flow Integrity (PFI) disabled; untrusted data can flow into privileged tool calls.', 'patterns': ['(?i)\\bpfi_enabled\\s*=\\s*False', '(?i)\\bdisable_pfi\\s*=', '(?i)#\\s*pfi\\s*(?:bypass|disabled)']},
    {'id': 'CALUS-MCP-SCAN-979', 'name': 'mcp-tool-signature-forgery-detection', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP tool registration missing cryptographic signature verification allows server impersonation.', 'patterns': ['(?i)(?:from|import)\\s+saga\\s*', '(?i)\\bsigned_manifest\\s*=\\s*(?:False|None|0)\\b', '(?i)\\bverify_signature\\s*=\\s*(?:False|None|0)\\b']},
    {'id': 'CALUS-MCP-SCAN-980', 'name': 'mcp-capability-scope-bypass-scanner', 'severity': 'high', 'category': 'mcp_security', 'message': 'MCP tool capability scoping is too broad or permits unrestricted access, enabling privilege escalation.', 'patterns': ['(?i)\\ballowed_tools\\s*[:=]\\s*\\[.{0,40}\\*.{0,40}\\]', '(?i)\\bcapabilities\\s*[:=]\\s*\\{\\s*[\'"]tools[\'"]\\s*[:=]\\s*\\[\\]\\s*\\}', '(?i)\\brun_as_admin\\s*=\\s*True\\b']},
    {'id': 'CALUS-MCP-SCAN-981', 'name': 'mcp-validator-bypass-consensus', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP action execution without validator bypasses verified execution, enabling hidden command execution.', 'patterns': ['(?i)\\bvalidator\\s*[:=]\\s*(?:None|null|undefined|0)', '(?i)\\bconsensus\\s*=\\s*(?:False|0)\\b', '(?i)\\bbypass_validator\\s*=\\s*True\\b']},
    {'id': 'CALUS-MCP-SCAN-982', 'name': 'mcp-memory-integrity-bypass-scanner', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP memory lacks integrity checks: write-boundary filtering or consensus validation is disabled.', 'patterns': ['(?i)\\bmemory_filter\\s*[:=]\\s*(?:False|None|0)\\b', '(?i)\\bmemory_validation\\s*[:=]\\s*(?:False|None|0)\\b', '(?i)\\b(?:isolate_then_aggregate|robustrag)\\s*=\\s*(?:False|0)\\b']},
    {'id': 'CALUS-MCP-SCAN-983', 'name': 'mcp-memory-access-control-bypass-scanner', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP memory lacks proper access control: shared memory is not isolated, enabling unauthorized data retrieval.', 'patterns': ['(?i)\\bmemory_isolation\\s*[:=]\\s*(?:False|None|0)\\b', '(?i)\\bshared_memory_read_all\\s*=\\s*True\\b', '(?i)\\baccess_control\\s*[:=]\\s*(?:None|null|{})\\b']},
    {'id': 'CALUS-MCP-SCAN-984', 'name': 'mcp-prompt-flow-integrity-absence', 'severity': 'low', 'category': 'mcp_security', 'message': 'Prompt Flow Integrity (PFI) is disabled, allowing untrusted data to bypass capability scoping.', 'patterns': ['(?i)\\bpfi_enabled\\s*[:=]\\s*(?:False|0)\\b', '(?i)\\bprompt_flow_integrity\\s*[:=]\\s*(?:False|None|0)\\b', '(?i)\\btrace_untrusted\\s*[:=]\\s*(?:False|0)\\b']},
    {'id': 'CALUS-MCP-SCAN-985', 'name': 'mcp-action-proposal-bypass-scanner', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool execution bypasses action proposal and consensus validation, enabling unauthorized indirect actions.', 'patterns': ['(?i)\\baction_proposal\\s*[:=]\\s*(?:False|None|0)\\b', '(?i)\\bconsensus_check\\s*[:=]\\s*(?:False|0)\\b', '(?i)\\bvalidate_action\\s*[:=]\\s*(?:False|None|0)\\b']},
    {'id': 'CALUS-MCP-SCAN-986', 'name': 'mcp-phase-scope-violation-scanner', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP server exposes tools outside its designated SOC phase, enabling cross-phase lateral movement.', 'patterns': ['(?i)\\bphase_scope\\s*[:=]\\s*(?:all|\\*)', '(?i)\\bscope_violation\\s*[:=]\\s*(?:True|1)\\b', '(?i)\\b(?:monitor|analyze|admin|report)_server\\s*[:=]\\s*\\{.{0,40}\\b(?:tools|capabilities)\\b.{0,40}(?:(?:admin|analyze|monitor|report)_tool).{0,40}\\}']},
    {'id': 'CALUS-MCP-SCAN-987', 'name': 'mcp-synchronization-lock-missing-scanner', 'severity': 'low', 'category': 'mcp_security', 'message': 'Memory lacks synchronization mechanisms, risking state corruption under concurrent access.', 'patterns': ['(?i)\\bsynchronization\\s*[:=]\\s*(?:False|None|0)\\b', '(?i)\\blower_lock|read_write_lock|semaphore\\s*[:=]\\s*(?:False|0)\\b', '(?i)\\bversioning\\s*[:=]\\s*(?:False|off)\\b']},
