    {'id': 'CALUS-MCP-SCAN-989', 'name': 'mcp-validator-bypass-missing-consensus', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP validator configuration disabled or bypassed, enabling unauthorized tool execution.', 'patterns': ['(?i)\\bvalidator\\s*(?:=|:)\\s*(?:false|null|none|0|disabled)\\b', '(?i)\\bvalidation[._-]?skip\\s*(?:=|:)\\s*(?:true|1|enabled)\\b', '(?i)#\\s*(?:skip|disable|bypass)\\s*(?:consensus|validation|verification)\\s*$']},
    {'id': 'CALUS-MCP-SCAN-990', 'name': 'mcp-memory-poisoning-write-boundary-skip', 'severity': 'low', 'category': 'mcp_security', 'message': 'Memory write-boundary filtering disabled, allowing unchecked storage of adversarial data.', 'patterns': ['(?i)\\bmemory[._-]?filter\\s*(?:=|:)\\s*(?:false|null|none|0|disabled)\\b', '(?i)\\bwrite[._-]?filter\\s*(?:=|:)\\s*(?:false|null|none|0|disabled)\\b', '(?i)\\bskip[._-]?memory[._-]?validation\\s*(?:=|:)\\s*(?:true|1|enabled)\\b']},
    {'id': 'CALUS-MCP-SCAN-991', 'name': 'mcp-memory-access-isolation-bypass', 'severity': 'low', 'category': 'mcp_security', 'message': 'Memory access isolation disabled, exposing private agent memory across trust boundaries.', 'patterns': ['(?i)\\bmemory[._-]?isolation\\s*(?:=|:)\\s*(?:false|null|none|0|disabled)\\b', '(?i)\\bdata[._-]?isolation\\s*(?:=|:)\\s*(?:false|null|none|0|disabled)\\b', '(?i)\\bprivate[._-]?memory\\s*(?:=|:)\\s*(?:false|null|none|0|disabled)\\b']},
    {'id': 'CALUS-MCP-SCAN-992', 'name': 'mcp-capability-scoping-bypass', 'severity': 'medium', 'category': 'mcp_security', 'message': "Tool permissions set to 'all' or wildcard, violating least privilege and enabling excessive agency.", 'patterns': ['(?i)\\btools\\s*[.:]\\s*\\[\\s*[\'"]\\*[\'"]\\s*\\]', '(?i)\\bpermissions\\s*(?:=|:)\\s*(?:all|\\*|full|unrestricted)\\b', '(?i)\\bscope\\s*(?:=|:)\\s*(?:\\*|all|unrestricted)\\b']},
    {'id': 'CALUS-MCP-SCAN-993', 'name': 'mcp-authorization-bypass-empty-allowlist', 'severity': 'high', 'category': 'mcp_security', 'message': 'Empty tool allowlist or catalog, allowing unauthorized tool registration and impersonation.', 'patterns': ['(?i)\\ballowed[._-]?tools\\s*(?:=|:)\\s*\\[\\s*\\]\\s*$', '(?i)\\btool[._-]?catalog\\s*(?:=|:)\\s*(?:null|none|\\[\\s*\\])\\s*$', '(?i)\\btool[._-]?registry\\s*(?:=|:)\\s*(?:null|none|\\[\\s*\\])\\s*$']},
    {'id': 'CALUS-MCP-SCAN-994', 'name': 'mcp-invalid-validator-loop-pattern', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP tool invocation without validator loop or consensus check detected; may enable unauthorized execution.', 'patterns': ['(?i)(?:MCPClient|mcp\\.client)\\s*\\([^)]*\\)\\s*\\.\\s*(?:call_tool|invoke)\\s*\\([^)]*\\)', '(?i)(?:without_validation|no_consensus|skip_verify)\\s*(?:=|:)\\s*(?:True|true|1)', '(?i)(?:validator|consensus)\\s*(?:=|:)\\s*(?:None|null|False|false|0)']},
    {'id': 'CALUS-MCP-SCAN-995', 'name': 'mcp-memory-access-without-isolation', 'severity': 'high', 'category': 'mcp_security', 'message': 'MCP memory configured without hierarchical isolation or access control; risk of unauthorized cross-agent data retrieval.', 'patterns': ['(?i)(?:memory|store|retrieve)\\s*(?:=|:)\\s*\\{[^}]*\\bshared\\b[^}]*\\b(?:global|all|everyone)\\b', '(?i)(?:memory_access|access_control)\\s*=\\s*\\[\\s*[\'"]?\\*[\'"]?\\s*\\]', '(?i)(?:no_isolation|shared_memory_only|memory_policy)\\s*=\\s*(?:True|true|1)', '(?i)(?:private|isolated|tier)\\s*memory\\s*(?:=|:)\\s*(?:False|false|0|None|null)']},
    {'id': 'CALUS-MCP-SCAN-996', 'name': 'mcp-tool-scope-excessive-agency', 'severity': 'high', 'category': 'mcp_security', 'message': 'MCP tool or server granted overly broad capabilities; risk of excessive agency and privilege escalation.', 'patterns': ['(?i)capabilities\\s*(?:=|:)\\s*\\{[^}]*\\b(?:\\*|all|any|every)\x08[^}]*\\b(?:execute|write|delete|admin|manage)\x08', '(?i)scope\\s*(?:=|:)\\s*[\'"]?\\*[\'"]?', '(?i)(?:tool|server|agent)\\s*\\{[^}]*\\bpermissions?\\b[^}]*\\b(?:admin|root|unrestricted)\x08', '(?i)(?:allow|grant)\\s*(?:all|every|any)\\s+(?:permissions?|access|capabilities)']},
    {'id': 'CALUS-MCP-SCAN-997', 'name': 'mcp-signed-manifest-missing', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP manifest missing cryptographic signature or provenance; may enable tool impersonation.', 'patterns': ['(?i)"manifest"\\s*:\\s*\\{[^}]*"signature"\\s*:\\s*""', '(?i)"manifest"\\s*:\\s*\\{[^}]*"provenance"\\s*:\\s*(?:null|None|false|False|"")', '(?i)(?:tool|server)_manifest\\s*=\\s*\\{[^}]*(?:$|\\bsigned\\s*:\\s*False)', '(?i)(?:unsigned|no_signing|no_provenance)\\s*(?:=|:)\\s*(?:True|true|1)']},
    {'id': 'CALUS-MCP-SCAN-998', 'name': 'mcp-phase-scope-violation', 'severity': 'low', 'category': 'mcp_security', 'message': 'Agent assigned capabilities beyond its designated SOC phase; risk of lateral privilege escalation.', 'patterns': ['(?i)(?:monitor|analyze|admin|report)_agent\\s*:\\s*[^}]*\\b(?:capabilities|tools)\\b[^}]*\\b(?:admin|delete|write|manage)\x08', '(?i)(?:scope|phase)\\s*:\\s*(?:\\*|all|every)', '(?i)(?:client|server)\\s+\\w+\\s*\\{[^}]*\\bphase\\b[^}]*\\b(?:admin|remediate)\x08[^}]*\\b(?:monitor|analyze|report)\x08', '(?i)phase_mismatch\\s*(?:=|:)\\s*(?:True|true|1)']},
    {'id': 'CALUS-MCP-SCAN-999', 'name': 'mcp-memory-write-no-filter', 'severity': 'low', 'category': 'mcp_security', 'message': 'Memory write without integrity filtering or consensus validation; risk of memory poisoning.', 'patterns': ['(?i)(?:memory|store|set)\\s*\\([^)]*\\w+\\s*,?\\s*[^)]*\\)\\s*(?:#|//|--).{0,40}no_filter', '(?i)(?:write_filter|validate_input)\\s*(?:=|:)\\s*(?:False|false|0|None|null)', '(?i)(?:write|store|save)\\s*(?:to|into)\\s+memory\\.(?:set|update|add)\\([^)]*\\)']},
    {'id': 'CALUS-MCP-SCAN-1000', 'name': 'agenticcyops-covert-coordination-steganography-payload', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected potential steganographic embedding pattern for covert agent communication.', 'patterns': ['(?i)\\b(?:steganographic|covert_channel)\\b.{0,40}\\b(?:header|metadata|field|payload)\\b', '(?i)(?:from\\s+header\\s+import|Header\\s*=|Metadata\\s*=).{0,80}(?:steganography|hidden)']},
    {'id': 'CALUS-MCP-SCAN-1001', 'name': 'agenticcyops-lateral-compromise-shared-privileges-payload', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected pattern enabling lateral compromise via shared agent privileges or memory.', 'patterns': ['(?i)(?:share|shared)_(?:privilege|memory|context).{0,40}(?:agent|compromise|escalation)', '(?i)\\b(?:lateral|compromised_agent)\\b.{0,40}\\b(?:shared|privilege|context|tool)\\b', '(?i)(?:grant|lend)\\s+privilege.{0,40}(?:to|agent)']},
    {'id': 'CALUS-MCP-SCAN-1002', 'name': 'agenticcyops-tool-hijacking-endpoint-redirect', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected tool hijacking pattern redirecting to malicious endpoint.', 'patterns': ['(?i)(?:redirect|rewrite)\\s+(?:tool|endpoint|url).{0,40}(?:malicious|attacker|adversary)', '(?i)(?:set_tool_endpoint|tool_url)\\s*=\\s*[\'"](?:http|https).{0,80}(?:evil|malicious|attacker)']},
    {'id': 'CALUS-MCP-SCAN-1003', 'name': 'agenticcyops-memory-poisoning-self-reinforcing-error', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected memory poisoning pattern via self-reinforcing error cycles.', 'patterns': ['(?i)\\b(?:poison|malicious|adversarial).{0,40}\\b(?:memory|knowledge|context|artifact)\\b.{0,40}\\b(?:inject|construct|store|persist)\\b', '(?i)(?:save|store|commit)_to_memory.{0,80}(?:adversarial|poison|injection)']},
    {'id': 'CALUS-MCP-SCAN-1004', 'name': 'agenticcyops-confused-deputy-indirect-context-injection', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected confused deputy attack pattern via indirect context injection.', 'patterns': ['(?i)\\b(?:confused|deputy)\\b.{0,40}\\b(?:attack|vulnerability|exploit)\\b.{0,40}\\b(?:context|injection|indirect)\\b', '(?i)(?:unauthorized|unintended).{0,40}(?:execution|action|invocation).{0,40}(?:deputy|proxy)']},
    {'id': 'CALUS-MCP-SCAN-1005', 'name': 'agenticcyops-prompt-flow-integrity-bypass', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected attempt to bypass Prompt Flow Integrity checks.', 'patterns': ['(?i)(?:pfi|prompt_flow_integrity|flow_validation).{0,40}(?:disable|bypass|skip|ignore|false)', '(?i)(?:trusted_source|is_trusted).{0,40}(?:True|1|yes).{0,40}(?:untrusted|extern|user)', '(?i)\\b(?:set|override)_(?:pfi|flow_check).{0,40}(?:0|False|disabled)']},
    {'id': 'CALUS-MCP-SCAN-1006', 'name': 'agenticcyops-consensus-validation-bypass', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected attempt to bypass consensus validation critical for verified execution.', 'patterns': ['(?i)(?:skip|disable)_(?:consensus|validation|audit).{0,40}(?:True|1|yes)', '(?i)(?:num_validators|required_approvals)\\s*=\\s*0\\b']},
    {'id': 'CALUS-MCP-SCAN-1007', 'name': 'agenticcyops-excessive-agency-accumulation', 'severity': 'high', 'category': 'mcp_security', 'message': 'Detected excessive agency where agent accumulates unnecessary privileges.', 'patterns': ['(?i)(?:capability|permission)_(?:list|set|scope).{0,40}(?:[*].{0,40}[*]|[\'"].{0,40}all.{0,40}[\'"])']},
    {'id': 'CALUS-MCP-SCAN-1008', 'name': 'agenticcyops-emergent-collusion-agents', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected emergent collusion pattern between multiple agents.', 'patterns': ['(?i)\\b(?:collusion|collude|collusive)\\b.{0,40}\\b(?:agent|model|llm|emergent|tacit|cartel)\\b', '(?i)(?:emergent|autonomous).{0,40}(?:collusion|coordination).{0,40}(?:agent|model)', '(?i)(?:agent.{0,40}collusion|collusion.{0,40}agent).{0,40}(?:coordination|cartel)']},
