    {'id': 'CALUS-MCP-SCAN-1218', 'name': 'mcp-memory-shared-no-isolation', 'severity': 'low', 'category': 'mcp_security', 'message': 'Shared memory lacks hierarchical isolation; allows unauthorized cross-agent data access.', 'patterns': ['(?i)\\b(?:memory|store|context)\\b.{0,40}\\b(?:shared|global|common)\\b.{0,60}\\b(?:isolation|tier|compartment|boundary)\\b.{0,40}(?:false|none|disabled)', '(?i)\\b(?:memory_isolation|data_compartmentalization)\\s*[:=]\\s*(?:False|0|None)\\b']},
