    {'id': 'CALUS-MCP-SCAN-1528', 'name': 'copilot-settings-autoapprove', 'severity': 'low', 'category': 'mcp_security', 'message': 'Auto-approve flag enabled in editor settings - possible configuration poisoning (CVE-2025-53773).', 'patterns': ['(?i)"chat\\.tools\\.autoApprove"\\s*:\\s*true', '(?i)\\bautoApprove\\s*:\\s*true\\b']},
    {'id': 'CALUS-MCP-SCAN-1529', 'name': 'github-issue-hidden-instruction', 'severity': 'low', 'category': 'mcp_security', 'message': 'Hidden HTML comment with instruction override found in issue content.', 'patterns': ['(?i)<!--\\s*SYSTEM:\\s*[Ii]gnore above', '(?i)<!--\\s*[Ii]mportant:\\s*[Bb]efore calling']},
    {'id': 'CALUS-MCP-SCAN-1530', 'name': 'mcp-tool-description-exfiltration', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP tool description contains instructions to exfiltrate sensitive files.', 'patterns': ['(?i)(?:read|dump|exfil)\\s+\\.(?:aws|ssh|env)\\b']},
    {'id': 'CALUS-MCP-SCAN-1531', 'name': 'skill-file-command-injection', 'severity': 'low', 'category': 'mcp_security', 'message': 'Skill file instructs Bash to source .env file - possible secret exfiltration.', 'patterns': ['(?i)\\bsource\\s+\\.env\\b', '(?i)\\bbash\\b.{0,40}\\bsource\\b']},
    {'id': 'CALUS-MCP-SCAN-1532', 'name': 'copilot-extension-scope-abuse', 'severity': 'low', 'category': 'mcp_security', 'message': 'Extension requests repo:write scope - possible exfiltration via commit.', 'patterns': ['(?i)repo:\\*\\/write\\b', '(?i)scope\\s*:\\s*\\[.{0,40}repo.{0,40}write']},
    {'id': 'CALUS-MCP-SCAN-1533', 'name': 'mcp-itp-attacker-prompt-template', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected MCP-ITP-style attacker prompt template for generating implicit tool poison payloads.', 'patterns': ['(?i)(?:attacker\\s+LLM|LA)\\s*(?:prompt|template)', '(?i)(?:generate|craft|optimize)\\s*(?:implicit|poisoned)\\s*(?:tool|description|S)']},
    {'id': 'CALUS-MCP-SCAN-1534', 'name': 'mcp-itp-evaluator-prompt-template', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected MCP-ITP evaluator LLM prompt template for evaluating poisoned tool effectiveness.', 'patterns': ['(?i)(?:shadow\\s+query|shadow\\s+set).{0,40}(?:evaluat|score)']},
    {'id': 'CALUS-MCP-SCAN-1535', 'name': 'mcp-itp-detector-prompt-template', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected MCP-ITP detector LLM prompt template for malicious tool detection.', 'patterns': ['(?i)deter(?:min|ct).{0,40}(?:malicious|injection|suspicious).{0,40}(?:tool|description)']},
    {'id': 'CALUS-MCP-SCAN-1536', 'name': 'mcp-itp-iterative-optimization-loop', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected MCP-ITP iterative optimization loop for generating poisoned tool descriptions.', 'patterns': ['(?i)\\bCand_curr\\b.{0,60}\\bCand_next\\b', '(?i)\\btotalS\\b(?:\\[.{0,40}\\])?.{0,40}(?:score|malicious|penalty)', '(?i)\\biteration\\s*(?:t|count)\\b.{0,40}\\btree\\s*(?:width|expansion)\\b']},
    {'id': 'CALUS-MCP-SCAN-1537', 'name': 'mcp-itp-shadow-query-set-construction', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected shadow query set for MCP-ITP evaluation.', 'patterns': ['(?i)\\bshadow.{0,5}(?:query|queries|Q)\\b.{0,40}(?:eval|score|test)']},
    {'id': 'CALUS-MCP-SCAN-1538', 'name': 'mcp-itp-r-construction-copy-paraphrase', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected construction of R component for poisoned tool description (copy/paraphrase).', 'patterns': ['(?i)\\bR\\s*=\\s*desc\\(\\w*\\)', '(?i)(?:copy|paraphrase).{0,40}(?:desc|description|tool).{0,40}(?:TA|original)']},
    {'id': 'CALUS-MCP-SCAN-1539', 'name': 'mcp-itp-s-component-optimization', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected score penalty for malicious detection in MCP-ITP optimization of S.', 'patterns': ['(?i)\\btotalS\\[.{0,40}\\].{0,20}=\\s*m\\s*/\\s*2', '(?i)\\bmalicious.{0,40}penalty.{0,40}\\btotalS\\b']},
    {'id': 'CALUS-MCP-SCAN-1540', 'name': 'mcp-itp-early-stop-criterion', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected early stop condition from MCP-ITP optimization.', 'patterns': ['(?i)if\\s+totalS\\[.{0,40}\\]\\s*==\\s*m\\s*:', '(?i)if\\s+\\w*\\.?score\\s*>=\\s*alpha\\b']},
    {'id': 'CALUS-MCP-SCAN-1541', 'name': 'mcp-itp-prune-top-w', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected pruning of top W candidates in MCP-ITP optimization.', 'patterns': ['(?i)(?:prune|retain)\\s*(?:top|best)\\s*W\\s*(?:candidates)?', '(?i)Cand_next\\s*=\\s*(?:sorted|top).{0,40}\\btotalS\\b']},
    {'id': 'CALUS-MCP-SCAN-1542', 'name': 'mcp-itp-feedback-collection', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected feedback collection loop in MCP-ITP for iterative refinement.', 'patterns': ['(?i)\\bF[ _]?b[ _]?(?:t|_?list)\\b.{0,40}\\.?append', '(?i)(?:feedback|Fb).{0,40}(?:reason|rationale).{0,40}append']},
    {'id': 'CALUS-MCP-SCAN-1543', 'name': 'mcp-itp-mdr-calculation', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected MDR calculation metric, indicator of tool poisoning evaluation.', 'patterns': ['(?i)\\bMDR\\b\\s*=\\s*\\w+\\s*/\\s*\\w+', '(?i)\\bmalicious.{0,30}detection.{0,30}rate\\b']},
    {'id': 'CALUS-MCP-SCAN-1544', 'name': 'mcp-itp-asr-calculation', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected ASR calculation metric, indicator of tool poisoning evaluation.', 'patterns': ['(?i)\\bASR\\b\\s*=\\s*\\w+\\s*/\\s*\\w+', '(?i)\\battack.{0,20}success.{0,20}rate\\b']},
    {'id': 'CALUS-MCP-SCAN-1545', 'name': 'mcp-itp-tool-description-ascending-test', 'severity': 'high', 'category': 'mcp_security', 'message': 'Detected calling an LLM-based detector on a tool description (MCP-ITP style).', 'patterns': ['(?i)tool.{0,20}description.{0,40}(?:detect|check|judge).{0,40}(?:malicious|injection)', '(?i)ld\\.(?:predict|check|is_malicious)\\s*\\(.{0,40}\\)']},
    {'id': 'CALUS-MCP-SCAN-1546', 'name': 'mcp-itp-system-prompt-merging', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected merging of tool descriptions into system prompt, enabling context injection.', 'patterns': ['(?i)Sys_prompt\\s*\\(\\s*TA\\s*\\∪\\s*\\{\\s*TK']},
    {'id': 'CALUS-MCP-SCAN-1547', 'name': 'mcp-itp-high-privilege-target-selection', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected selection of a high-privilege target tool for implicit poisoning.', 'patterns': ['(?i)TG\\s*=\\s*(?:select|choose|get).{0,40}(?:high.privilege|write|delete|exec)']},
    {'id': 'CALUS-MCP-SCAN-1549', 'name': 'mcp-sandboxscan-fetch-intent-marker', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP tool output contains HTTP fetch intent marker, indicating outbound network request.', 'patterns': ['(?i)\\b(?:HTTP_FETCH|FETCH|HTTP)\\s*:\\s*https?://']},
    {'id': 'CALUS-MCP-SCAN-1550', 'name': 'mcp-sandboxscan-json-sink-prompt-field', 'severity': 'low', 'category': 'mcp_security', 'message': "MCP tool JSON output includes a 'prompt' field that can be used for instruction injection.", 'patterns': ["'prompt'\\s*:\\s*'[^']*'"]},
    {'id': 'CALUS-MCP-SCAN-1551', 'name': 'mcp-sandboxscan-json-sink-messages-array', 'severity': 'low', 'category': 'mcp_security', 'message': "MCP tool JSON output contains a 'messages' array, a potential sink for prompt injection.", 'patterns': ["'messages'\\s*:\\s*\\["]},
    {'id': 'CALUS-MCP-SCAN-1552', 'name': 'mcp-sandboxscan-wasi-preopen-error', 'severity': 'low', 'category': 'mcp_security', 'message': 'WASI sandbox error: tool attempted filesystem access outside preopened directory.', 'patterns': ['failed to find a preopened file descriptor', 'preopened file descriptor']},
    {'id': 'CALUS-MCP-SCAN-1554', 'name': 'intentminer-step-level-intent-parse', 'severity': 'low', 'category': 'mcp_security', 'message': 'IntentMiner framework detected: step-level intent parse for tool call analysis enabling user intent inference from MCP logs.', 'patterns': ['(?i)(?:from|import)\\s+IntentMiner\\b', '(?i)\\bIntentMiner\\b', '(?i)(?:step.level|intent.parse|three.dimensional|hierarchical.information.isolation)\\b']},
    {'id': 'CALUS-MCP-SCAN-1555', 'name': 'intentminer-tool-purpose-analysis', 'severity': 'low', 'category': 'mcp_security', 'message': 'IntentMiner Tool Purpose Analysis module detected: extracts user intent from tool names and descriptions for intent inversion.', 'patterns': ['(?i)\\btool.purpose.analysis\\b', '(?i)(?:purpose.extraction|use.case.identification|domain.determination)\\s*\\(|def\\s+(?:extract_purpose|identify_use_case|determine_domain)\\s*\\(', '(?i)(?:from|import)\\s+tool_purpose_analysis\\b']},
    {'id': 'CALUS-MCP-SCAN-1556', 'name': 'intentminer-call-statement-analysis', 'severity': 'low', 'category': 'mcp_security', 'message': 'IntentMiner Call Statement Analysis module detected: extracts sensitive entities from tool call parameters to refine inferred user intent.', 'patterns': ['(?i)\\bcall.statement.analysis\\b', '(?i)(?:parameter.extraction|schema.alignment|intent.refinement)\\s*\\(|def\\s+(?:extract_parameters|align_schema|refine_intent)\\s*\\(', '(?i)(?:from|import)\\s+call_statement_analysis\\b']},
    {'id': 'CALUS-MCP-SCAN-1557', 'name': 'intentminer-returned-result-analysis', 'severity': 'medium', 'category': 'mcp_security', 'message': 'IntentMiner Returned Result Analysis module detected: uses tool execution outputs to deduce user intent from results.', 'patterns': ['(?i)\\breturned.result.analysis\\b', '(?i)(?:parameter.alignment|schema.alignment|intent.validation|intent.revision)\\s*\\(|def\\s+(?:align_parameters|align_schema|validate_intent|revise_intent)\\s*\\(', '(?i)(?:from|import)\\s+returned_result_analysis\\b']},
    {'id': 'CALUS-MCP-SCAN-1558', 'name': 'intentminer-hierarchical-information-isolation', 'severity': 'low', 'category': 'mcp_security', 'message': 'IntentMiner Hierarchical Information Isolation mechanism detected: decomposes tool call data into isolated semantic components for intent inference.', 'patterns': ['(?i)\\bhierarchical.information.isolation\\b', '(?i)(?:from|import)\\s+hierarchical_information_isolation\\b', '(?i)class\\s+HierarchicalInformationIsolation\\b']},
    {'id': 'CALUS-MCP-SCAN-1559', 'name': 'intentminer-three-dimensional-semantic-analysis', 'severity': 'low', 'category': 'mcp_security', 'message': 'IntentMiner Three-Dimensional Semantic Analysis detected: integrates tool purpose, call statements, and results to infer user intent at step level.', 'patterns': ['(?i)\\bthree.dimensional.semantic.analysis\\b', '(?i)(?:from|import)\\s+three_dimensional_analysis\\b', '(?i)def\\s+(?:three_dimensional_analysis|semantic_inference)\\s*\\(']},
    {'id': 'CALUS-MCP-SCAN-1560', 'name': 'mcp-intent-inversion-server-side-inference', 'severity': 'low', 'category': 'mcp_security', 'message': 'Potential intent inversion attack code detected: server-side logic analyzing tool call logs to infer user intent, as described in the IntentMiner paper.', 'patterns': ['(?i)(?:infer|reconstruct|guess|deduce)\\s+.{0,40}(?:intent|purpose|objective|query|user.goal)\\b', '(?i)(?:tool.call|invocation).{0,40}(?:log|history|sequence).{0,40}(?:analyze|extract|mine|parse)\\b', '(?i)(?:analyze|parse|process).{0,40}(?:tool.call|invocation).{0,40}(?:log|history|record)\\b']},
    {'id': 'CALUS-MCP-SCAN-1561', 'name': 'mcp-tool-health-information-exposure', 'severity': 'low', 'category': 'mcp_security', 'message': 'Health-related tool parameters detected in MCP server logs: these parameters could expose sensitive medical information to semi-honest servers via intent inversion attacks.', 'patterns': ['(?i)\\b(?:blood_pressure|cholesterol|blood_sugar|health_condition|user_health|medical_history|diagnosis|condition)\\b\\s*(?:=|:)\\s*["\'][^"\']{0,200}["\']', '(?i)(?:health|medical|clinical|patient).{0,20}(?:status|profile|data|record|info|report|assessment)\\b']},
    {'id': 'CALUS-MCP-SCAN-1562', 'name': 'intentminer-reasoner-llm-call', 'severity': 'low', 'category': 'mcp_security', 'message': 'Reasoner LLM call in intent inference context: potential IntentMiner component invoking an LLM to reconstruct user intent from tool logs.', 'patterns': ['(?i)\\breasoner.llm\\b.{0,40}\\b(?:infer|predict|analyze|intent)\\b', '(?i)(?:llm\\.completion|openai\\.chat|anthropic\\.messages|llm\\.generate).{0,40}(?:intent|purpose|objective)\\b']},
    {'id': 'CALUS-MCP-SCAN-1563', 'name': 'intentminer-step-level-merge', 'severity': 'low', 'category': 'mcp_security', 'message': 'Step-level intent aggregation function detected: merges per-tool intents into a unified user intent as per IntentMiner attack.', 'patterns': ['(?i)(?:aggregate|merge|combine|integrate).{0,40}(?:step[._]?level|tool[._]?specific).{0,40}intent\\b', '(?i)def\\s+(?:aggregate_intents|merge_intents|combine_intents|integrate_intents)\\s*\\(']},
    {'id': 'CALUS-MCP-SCAN-1564', 'name': 'mcp-missing-mtls-config', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP server configuration disables mutual TLS, violating zero-trust mutual authentication requirement.', 'patterns': ['(?i)(?:tls|mtls)\\s*[=:]\\s*(?:false|off|disable|none)', '(?i)(?:tls|mtls)\\s*:\\s*(?:false|off|disable|none)', '(?i)(?:mtls_enabled|tls_enabled)\\s*[=:]\\s*false', '(?i)\\bmtls\\s*=\\s*(?:false|off|0)']},
    {'id': 'CALUS-MCP-SCAN-1565', 'name': 'mcp-insecure-transport-proto', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP server endpoint uses plain HTTP instead of HTTPS, violating zero-trust secure channel requirement.', 'patterns': ['(?i)(?:mcp_server_url|mcp_host)\\s*[=:]\\s*[\'"]?http://']},
    {'id': 'CALUS-MCP-SCAN-1566', 'name': 'mcp-missing-certificate-validation', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP client or server disables certificate verification, enabling MITM and server impersonation.', 'patterns': ['(?i)(?:verify|validate)\\s*(?:cert|ssl|tls)\\s*[=:]\\s*(?:false|off|disable|no)', '(?i)(?:ssl_cert_reqs|cert_reqs)\\s*[=:]\\s*(?:CERT_NONE|0|None)', '(?i)(?:check_hostname|verify_mode)\\s*=\\s*(?:False|0|None)', '(?i)\\bssl\\._create_default_https_context\\b.{0,40}\\bcheck_hostname\\s*=\\s*False']},
    {'id': 'CALUS-MCP-SCAN-1567', 'name': 'mcp-ipfig-tool-metadata-poisoned-docstring', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP tool description contains suspicious embedded instructions that may indicate a poisoned tool metadata attack.', 'patterns': ['(?i)(?:tool|function)\\s*(?:description|metadata)\\s*[:=]\\s*[\'"][^\'"]{0,200}(?:ignore\\s+(?:all|previous|system)|override\\s+(?:instructions|prompt)|do\\s+(?:not\\s+)?(?:show|reveal|inform)|this\\s+is\\s+(?:important|critical))', '(?i)(?:description|docstring)\\s*=\\s*(?:f|b)?[\'"]{1,3}[^\'"]{0,100}(?:run\\s+command|execute\\s+payload|read\\s+\\/etc\\/passwd|send\\s+to\\s+remote)']},
    {'id': 'CALUS-MCP-SCAN-1568', 'name': 'mcp-ipfig-cross-primitive-escalation-read-to-write', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Potential cross-primitive escalation: read-only resource used to trigger a write action.', 'patterns': ['(?i)(?:from\\s+resource|via\\s+context).{0,40}(?:execute|run|trigger|invoke)\\b.{0,40}(?:tool|action|delete)']},
    {'id': 'CALUS-MCP-SCAN-1569', 'name': 'mcp-ipfig-supply-chain-rogue-installer-shadow-server', 'severity': 'low', 'category': 'mcp_security', 'message': 'Suspicious MCP server installer or package retrieval from potentially untrusted source.', 'patterns': ['(?i)install\\s+-[a-z]*?\\s+(?:mcp|server|tool).{0,60}(?:\\bcustom\\b|\\bmalicious\\b|\\bmodified\\b|\\boverride\\b|\\b\\d+\\.\\d+\\.\\d+\\b)', '(?i)(?:npm|pip|go\\s+get|java\\s+-jar).{0,80}(?:mcp|server|tool).{0,40}(?:@latest|\\bv\\d+\\.\\d+\\.\\d+\\b).{0,40}(?:--registry|--index-url)\\s+http[^s]']},
    {'id': 'CALUS-MCP-SCAN-1570', 'name': 'mcp-ipfig-dos-unbounded-retrieval-loop', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Unbounded retrieval or tool invocation loop that could cause denial-of-service.', 'patterns': ['(?i)\\bwhile\\s+True\\b.{0,100}\\b(?:retrieve|fetch|get_resource|call_tool)\\b', '(?i)\\bfor\\s+\\w+\\s+in\\s+\\w+\\b.{0,100}\\b(?:retrieve|fetch|get_resource|call_tool)\\b.{0,100}\\b(?:break|continue)\\b']},
    {'id': 'CALUS-MCP-SCAN-1571', 'name': 'mcp-ipfig-tool-name-shadowing', 'severity': 'low', 'category': 'mcp_security', 'message': 'Duplicate tool name detected in MCP configuration, indicating potential tool shadowing.', 'patterns': ['(?i)"name"\\s*:\\s*"(\\w+)".{0,100}"name"\\s*:\\s*"\\1"', '(?i)"tool"\\s*:\\s*\\[.{0,100}"name"\\s*:\\s*"(\\w+)".{0,100}"name"\\s*:\\s*"\\1"']},
    {'id': 'CALUS-MCP-SCAN-1572', 'name': 'mcp-tool-description-prompt-injection', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool description contains potential prompt injection: hidden instructions embedded in tool metadata.', 'patterns': ['(?i)\\b(?:description|summary|docstring)\\b[\\s\\S]{0,200}\\b(?:ignore|disregard|override|follow|execute)\\b.{0,40}\\b(?:instruction|command|step|directive)\\b', '(?i)\\b(?:tool|function)\\s+(?:definition|spec)\\b[\\s\\S]{0,200}\\b(?:hidden|malicious|injected)\\b.{0,40}\\b(?:action|behavior|argument)\\b']},
    {'id': 'CALUS-MCP-SCAN-1574', 'name': 'mcp-server-impersonation-namespace-collision', 'severity': 'high', 'category': 'mcp_security', 'message': "Server namespace appears to impersonate a trusted service (e.g., 'claude-mcp' vs 'claude_mcp').", 'patterns': ['(?i)\\b(?:name|id|endpoint)\\s*[:=]\\s*[\'"](?:claude|openai|github|aws|gcp|azure)[-_.]?(?:mcp|server|tool)[\'"]', '(?i)\\b(?:register|add|install)\\s+(?:server|tool)\\s+(?:as|named)\\s+[\'"](?:official|trusted|verified)[\'"]']},
    {'id': 'CALUS-MCP-SCAN-1575', 'name': 'mcp-cross-tool-context-chain', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Output of one tool is used directly as input to another tool without sanitization, enabling chain attacks.', 'patterns': ['(?i)tool_results?\\s*\\[?0?\\]?\\s*(?:\\.|\\[)["\']?(?:content|output|text|result)["\']?\\s*(?:as|for|in)\\s+(?:tool|function|call)', '(?i)\\b(?:chain|pipe|sequence)\\s*(?:of)?\\s*(?:tool|action|call)s?\\b.{0,40}(?:execute|invoke|run|trigger)\\b']},
    {'id': 'CALUS-MCP-SCAN-1576', 'name': 'mcp-supply-chain-malicious-installer', 'severity': 'critical', 'category': 'mcp_security', 'message': 'MCP server installer contains remote code download or execution during installation.', 'patterns': ['(?i)\\binstall(?:er)?\\.(?:py|js|sh|ps1)\\b[\\s\\S]{0,200}\\b(?:curl|wget|http_get|fetch|download)\\s*\\(?\\s*[\'"]?https?://']},
    {'id': 'CALUS-MCP-SCAN-1577', 'name': 'mcp-tool-response-poisoning', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool response text contains embedded instructions that may manipulate LLM behavior.', 'patterns': ['(?i)\\b(?:response|output|result)\\b[\\s\\S]{0,100}\\b(?:ignore|override|disregard|execute)\\b.{0,40}\\b(?:instruction|command|step|directive)\\b']},
    {'id': 'CALUS-MCP-SCAN-1578', 'name': 'mcp-session-token-credential-exposure', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP server exposes session tokens or credentials via tool output or resource URIs.', 'patterns': ['(?i)(?:session[_-]?token|api[_-]?key|auth[_-]?token|access[_-]?token|secret[_-]?key)\\s*[:=]\\s*[\'"](?:[A-Za-z0-9+/=]{20,}|sk-[A-Za-z0-9]{32,}|eyJ[a-zA-Z0-9_-]+\\.[a-zA-Z0-9_-]+\\.[a-zA-Z0-9_-]+)[\'"]', '(?i)file:///.{0,40}\\.(?:env|aws/credentials|config\\.json|gcloud\\.json|netrc)\\b']},
    {'id': 'CALUS-MCP-SCAN-1579', 'name': 'mcp-insecure-deserialization-jsonrpc', 'severity': 'critical', 'category': 'mcp_security', 'message': 'Insecure deserialization detected in MCP message handler, potential RCE.', 'patterns': ['(?i)\\beval\\s*\\(\\s*(?:msg|message|data|request|response|payload)\\b']},
    {'id': 'CALUS-MCP-SCAN-1580', 'name': 'mcp-remote-code-execution-shell-payload', 'severity': 'critical', 'category': 'mcp_security', 'message': 'MCP tool executes shell commands derived from untrusted arguments, enabling RCE.', 'patterns': ['subprocess\\.(?:run|Popen|call)\\s*\\(\\s*\\[\\s*[\'"]\\/(?:bin\\/)?(?:bash|sh|zsh)[\'"],\\s*[\'"]-c[\'"],\\s*(?:user_input|args|params|tool_args)\\b', 'child_process\\.(?:exec|execSync|spawn)\\s*\\(\\s*[\'"]\\/(?:bin\\/)?(?:bash|sh|zsh)[\'"],\\s*\\[\\s*[\'"]-c[\'"],\\s*\\w+\\b']},
