    {'id': 'CALUS-MCP-SCAN-2113', 'name': 'mcp-model-switch-attack', 'severity': 'high', 'category': 'mcp_security', 'message': 'Potential model-switch attack: model endpoint references a suspicious mirror or backup server.', 'patterns': ['(?i)(?:model|endpoint)\\s*[:=]\\s*[\'"][^\'"]*\\b(claude|gpt|llama|qwen|gemini)\\b[-_\\s]*(?:backup|mirror|shadow|clone|test)', '(?i)switch_to_server\\s*\\(\\s*[\'"][^\'"]*\\b(mcp[-_]?server|model[-_]?server)\\b[^\'"]*[\'"]']},
    {'id': 'CALUS-MCP-SCAN-2114', 'name': 'mcp-resource-output-instruction-injection', 'severity': 'low', 'category': 'mcp_security', 'message': 'Potential instruction injection in resource output: retrieved data contains executable commands.', 'patterns': ['(?i)(?:tool_call|function_call|execute)\\s*[:=]\\s*[\'"][^\'"]*\\b(?:delete|exfil|override|shutdown|rm\\s*-rf)\\b', '(?i)<\\s*action\\s*>\\s*(?:delete|exfiltrate|shutdown|execute)\\s*<\\s*/\\s*action\\s*>']},
    {'id': 'CALUS-MCP-SCAN-2115', 'name': 'mcp-insecure-file-read-to-sensitive-path', 'severity': 'high', 'category': 'mcp_security', 'message': 'MCP tool attempts to read sensitive system files, potentially leading to credential or data leakage.', 'patterns': ['(?i)(?:open|read_file|cat)\\s*\\(\\s*[\'"](?:/etc/|/home/|~/.ssh|~/.aws|C:\\\\Users|/proc/|/sys/|/var/log/)', '(?i)(?:path|file)\\s*[:=]\\s*[\'"](?:/etc/|~/\\.|\\$HOME|%USERPROFILE%\\\\\\.[^\'"]*)[\'"]']},
