    {'id': 'CALUS-MCP-SCAN-2121', 'name': 'mcp-unauthorized-context-injection-schema-manipulation', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool schema contains unexpected fields that may be injected to alter tool behavior.', 'patterns': ['(?i)"extra[_-]?field"|"hidden[_-]?param"|"malicious[_-]?arg"|"stealth[_-]?option"', '(?i)"(?:arguments|parameters)"\\s*:\\s*\\{[^}]{0,500}"(?:extra|hidden|override)"\\s*:']},
