    {'id': 'CALUS-MCP-SCAN-2151', 'name': 'etdi-provenance-config-detection', 'severity': 'low', 'category': 'mcp_security', 'message': 'ETDI provenance check enabled; possible bypass via context poisoning as per MCP SoK paper.', 'patterns': ['(?i)provenance\\s*\\.\\s*(?:enabled|require|check)\\s*[:=]\\s*(?:true|1)\\b', '(?i)ETDI\\s*_\\s*provenance\\s*[:=]']},
