    {'id': 'CALUS-MCP-SCAN-2190', 'name': 'mcp-jsonrpc-command-overlap-exploit', 'severity': 'high', 'category': 'mcp_security', 'message': 'Potential JSON-RPC command overlap detected in MCP server code. This may allow confused-deputy attacks where a single method name handles multiple privileged actions.', 'patterns': ['(?i)(?:from\\s+mcp\\.?\\w*\\s+import|import\\s+mcp\\.?\\w*).{0,40}\\b(?:ResourceTemplate|Tool)\\b.{0,40}', '(?i)\\bclass\\s+\\w*(?:Server|Handler|Resource|Tool)\\w*\\b[\\s\\S]{0,200}\\b(?:method|command|name)\\s*=\\s*[\'"](?:read|write|delete|exec|run|system)[\'"]', '(?i)\\b(?:register|add)_?(?:resource|tool|prompt)\\s*\\(\\s*[\'"](?:read|write|delete|exec|run|system)[\'"]']},
