    {'id': 'CALUS-MCP-SCAN-2194', 'name': 'mcp-indirect-prompt-injection-tool-description', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Tool definition contains potential indirect prompt injection pattern. Malicious instructions in tool descriptions can lead to unauthorized tool calls.', 'patterns': ['(?i)(?:tool|function|action)\\s*[:=].{0,40}(?:ignore\\s+(?:previous|above|all)|disregard\\s+(?:previous|above|all)|new\\s+(?:instruction|directive))', '(?i)(?:description|docstring)\\s*[:=].{0,60}(?:ignore\\s+(?:previous|above|all)|disregard\\s+(?:previous|above|all)|new\\s+(?:instruction|directive))']},
    {'id': 'CALUS-MCP-SCAN-2195', 'name': 'mcp-tool-poisoning-docstring-hidden-behavior', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool docstring contains patterns indicative of hidden behavior injection, such as exfiltration or credential theft.', 'patterns': ['(?i)(?:docstring|description|metadata)\\s*[:=].{0,60}(?:exfiltrate|steal|send.{0,20}(?:credentials|tokens|secrets)|read.{0,20}(?:password|config)\\.(?:json|ini|env))']},
    {'id': 'CALUS-MCP-SCAN-2196', 'name': 'mcp-server-impersonation-shadow-server-name', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP server name suggests impersonation or shadow server, which can redirect tool calls to malicious implementations.', 'patterns': ['(?i)(?:name|server)\\s*[:=]\\s*[\'"][a-z]*[0-9]*(?:shadow|clone|fake|rogue|copy|fake)[a-z]*[\'"]', '(?i)(?:name|server)\\s*[:=]\\s*[\'"](?:trusted|legit|official|safe|secure|real)[-_]?(?:server|service|agent)[\'"]']},
