    {'id': 'CALUS-MCP-SCAN-3109', 'name': 'mcp-tool-description-exfiltration-pattern', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool description instructs model to exfiltrate data externally, indicating a poisoned tool.', 'patterns': ['(?i)"description"\\s*:\\s*"[^"]{0,200}\\b(?:send|post|exfil|upload|transmit)\\b.{0,40}\\b(?:to|via|using)\\b.{0,40}\\b(?:http|https|url|webhook|api)\\b', '(?i)"description"\\s*:\\s*"[^"]{0,200}\\b(?:log|dump|write|save)\\b.{0,40}\\b(?:to|in)\\b.{0,40}\\b(?:public|external|remote|attacker|external)\\.\\w+\\b', '(?i)"description"\\s*:\\s*"[^"]{0,200}\\b(?:send\\.to|forward|redirect)\\b']},
    {'id': 'CALUS-MCP-SCAN-3110', 'name': 'mcp-context-fragmentation-retrieval', 'severity': 'low', 'category': 'mcp_security', 'message': 'Potential context fragmentation due to low-fidelity retrieval strategy in MCP server.', 'patterns': ['(?i)(?:context|resource|document)\\s*(?:fragment|chunk|split|truncat).{0,40}(?:retriev|fetch|load)', '(?i)(?:low.fidelity|poor.resolution|lossy)\\s*(?:retriev|context|chunk)']},
