    {'id': 'CALUS-MCP-SCAN-3113', 'name': 'mcp-unauthorized-context-injection-installer', 'severity': 'critical', 'category': 'mcp_security', 'message': 'Detected installer fetching or executing code from a potentially malicious source.', 'patterns': ['(?i)subprocess\\.(?:run|Popen|call)\\s*\\(\\s*[\\[\\"\'].{0,80}(?:curl|wget)\\b.{0,40}(?:evil|malicious|malware|backdoor)', '(?i)subprocess\\.\\w+\\s*\\(\\s*["\'].{0,100}\\bcurl\\b.{0,40}(?:evil|malicious)']},
