    {'id': 'CALUS-MCP-SCAN-3115', 'name': 'mcp-cross-session-contamination-persistence', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected persistent storage of MCP state that could allow cross-session contamination.', 'patterns': ['(?i)(?:save|store|write|persist)\\s*\\(\\s*["\'].{0,60}(?:mcp_cache|mcp_state|tool_registry|shared_context)', '(?i)(?:pickle\\.dump|json\\.dump|open\\(.{0,40}[\'"]w[\'"]).{0,100}(?:mcp|context|tool)']},
