    {'id': 'CALUS-MCP-SCAN-3119', 'name': 'mcp-etdi-implementation-pattern', 'severity': 'medium', 'category': 'mcp_security', 'message': "Found code modifying tool descriptions at runtime, violating immutability principles in MCP's Enhanced Tool Definition Interface.", 'patterns': ['(?i)\\.(?:set_tool_description|update_tool_metadata)\\s*\\(.{0,80}(?:lambda|def|function)\\s+.{0,40}:']},
