    {'id': 'CALUS-MCP-SCAN-3123', 'name': 'mcp-unbounded-resource-retrieval', 'severity': 'high', 'category': 'mcp_security', 'message': 'Unbounded resource retrieval detected, can lead to denial-of-service via resource exhaustion.', 'patterns': ['(?i)while\\s+True\\s*:.{0,60}(?:read|fetch|get|retrieve)\\s*\\([^)]*\\)', '(?i)(?:recursive|infinite|loop).{0,40}(?:read|fetch|get|retrieve).{0,40}(?:resource|data|file)', '(?i)\\.(?:read_all|fetch_all|get_all)\\s*\\([^)]*\\)']},
    {'id': 'CALUS-MCP-SCAN-3124', 'name': 'mcp-session-token-hardcoded-exposure', 'severity': 'critical', 'category': 'mcp_security', 'message': 'Hardcoded MCP session token or API key detected, risk of session hijacking.', 'patterns': ['(?i)(?:mcp_token|mcp_session|mcp_api_key)\\s*=\\s*[\'"][A-Za-z0-9_\\-]{16,}[\'"]', '(?i)(?:bearer|token)\\s*:\\s*[\'"][A-Za-z0-9_\\-]{16,}[\'"].{0,60}(?:mcp|session)', '(?i)os\\.environ\\.get\\([\'"](?:MCP_TOKEN|MCP_SESSION|MCP_API_KEY)[\'"]']},
