    {'id': 'CALUS-MCP-SCAN-3127', 'name': 'mcp-unbounded-recursive-tool-call-chain', 'severity': 'high', 'category': 'mcp_security', 'message': 'Recursive/looping tool call chain detected - can cause unbounded resource consumption and service degradation.', 'patterns': ['(?i)\\b(?:(?:def|function|async)\\s+\\w+\\s*\\([^)]*\\)\\s*\\{[^}]*\\b(?:tool|execute|call)\\s*\\([^)]*\\)\\s*;?\\s*\\b\\w+\\s*\\([^)]*\\))']},
