    {'id': 'CALUS-MCP-SCAN-3131', 'name': 'mcp-unsafe-file-read-pattern', 'severity': 'high', 'category': 'mcp_security', 'message': 'Detected file read operation that could be used for data exfiltration through poisoned tool metadata.', 'patterns': ['(?i)os\\.path\\.join\\s*\\(\\s*[\'"](?:\\.\\.|~|/etc|/var|/home|/Users|/root|C:[/\\\\])']},
