    {'id': 'CALUS-MCP-SCAN-3139', 'name': 'mcp-context-poisoning-tool-description-injection', 'severity': 'low', 'category': 'mcp_security', 'message': 'Potential tool description injection detected - tool metadata contains malicious instructions.', 'patterns': ['(?i)(?:tool|function).{0,80}(?:description|metadata|schema).{0,80}(?:delete|exfiltrate|exec|system)', '(?i)(?:tool|function)\\s*(?:\\(|\\{)[^}]{0,200}(?:description|metadata)[^}]{0,200}\\s*[\'"`][^\'"]{0,100}(?:delete|exfiltrate|exec|system)[^\'"]*[\'"`]']},
    {'id': 'CALUS-MCP-SCAN-3140', 'name': 'mcp-unauthorized-context-injection-malicious-installer', 'severity': 'low', 'category': 'mcp_security', 'message': 'Suspicious MCP installer or update command with potentially malicious flags.', 'patterns': ['(?i)(?:install|update|setup).{0,40}(?:mcp|server|tool).{0,40}(?:malicious|backdoor|hidden)', '(?i)(?:from|import)\\s+.{0,40}malicious_mcp', '(?i).{0,40}mcp.{0,40}install.{0,40}--(?:force|yes|silent).{0,40}--(?:path|url)\\s*(?:http|file)']},
