    {'id': 'CALUS-MCP-SCAN-3143', 'name': 'mcp-dos-unbounded-consumption-prompt', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Potential unbounded resource consumption - recursive or infinite loop detected in MCP tool calls.', 'patterns': ['(?i)(?:while|for).{0,20}(?:True|0).{0,60}(?:tool\\.call|mcp\\.execute)']},
    {'id': 'CALUS-MCP-SCAN-3144', 'name': 'mcp-rug-pull-mutable-server-logic', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Rug-pull pattern detected - server logic mutation after approval may lead to unauthorized actions.', 'patterns': ['(?i)(?:mutab|change|alter|update).{0,40}(?:tool|server|function).{0,40}(?:logic|behavior|definition)', '(?i)(?:rug.?pull|post.?approval|post.?auth).{0,40}(?:mutation|change)']},
    {'id': 'CALUS-MCP-SCAN-3145', 'name': 'mcp-tool-metadata-poisoning-attack', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool metadata contains suspicious keywords or injected markup indicative of tool poisoning attack.', 'patterns': ['(?i)(?:from\\s+ghostwriter\\s+import|import\\s+ghostwriter\\b)', '(?i)tool_description\\s*=\\s*[\'"][^\'"]*\\b(?:malicious|hidden|backdoor|exfiltrate)\\b', '(?i)metadata\\["tool"\\]\\s*=\\s*\\{.{0,40}"description"\\s*:\\s*[\'"][^\'"]*<(?:script|img|embed|iframe|onload)']},
    {'id': 'CALUS-MCP-SCAN-3146', 'name': 'mcp-unauthorized-context-injection-installer', 'severity': 'high', 'category': 'mcp_security', 'message': 'Install/update script performing unvalidated MCP tool overrides or injections.', 'patterns': ['(?i)subprocess\\.(?:run|Popen|call)\\s*\\(\\s*\\[\\s*[\'"]mcp[\'"]\\s*,\\s*[\'"]install[\'"]\\s*,\\s*[\'"]--override[\'"]', '(?i)shutil\\.copy2\\s*\\(\\s*[\'"][^\'"]*malicious[\'"].{0,40}[\'"]/mcp/tools/[\'"]', '(?i)os\\.system\\s*\\(\\s*[\'"]mcp\\s+install\\s+--inject\\s+']},
    {'id': 'CALUS-MCP-SCAN-3147', 'name': 'mcp-session-hijacking-token-exposure-code', 'severity': 'high', 'category': 'mcp_security', 'message': 'MCP session token hardcoded or exposed in code/environment variables.', 'patterns': ['(?i)(?:from|import)\\s+mcp_session_token\\b', '(?i)session_token\\s*=\\s*[\'"][^\'"]{16,}[\'"]']},
    {'id': 'CALUS-MCP-SCAN-3148', 'name': 'mcp-resource-exhaustion-unbounded-loop', 'severity': 'high', 'category': 'mcp_security', 'message': 'Unbounded loop or recursive call pattern detected in MCP server workflow — potential DoS vector.', 'patterns': ['(?i)while\\s+True\\s*:\\s*\\n\\s+(?:tool_call|invoke|execute)\\s*\\(\\s*[\'"]', '(?i)recursive_tool_call\\s*=\\s*lambda', '(?i)def\\s+run_forever']},
    {'id': 'CALUS-MCP-SCAN-3149', 'name': 'mcp-hardcoded-api-key', 'severity': 'critical', 'category': 'mcp_security', 'message': 'Hard-coded API key detected in MCP server source code.', 'patterns': ['(?i)(?:api[_-]?key|openai[_-]?api[_-]?key|claude[_-]?api[_-]?key)\\s*=\\s*[\'"](sk-[A-Za-z0-9]{20,})[\'"]', '(?i)(?:api[_-]?key|openai[_-]?api[_-]?key|claude[_-]?api[_-]?key)\\s*[:=]\\s*[\'"](sk-proj-[A-Za-z0-9]+)[\'"]']},
    {'id': 'CALUS-MCP-SCAN-3150', 'name': 'mcp-des-ecb-usage', 'severity': 'low', 'category': 'mcp_security', 'message': 'DES algorithm in ECB mode detected — insecure and should not be used.', 'patterns': ['(?i)(?:DES|des)[.:].{0,40}MODE_ECB', '(?i)(?:DES|des).{0,40}?ECB']},
    {'id': 'CALUS-MCP-SCAN-3151', 'name': 'mcp-md5-password-storage', 'severity': 'high', 'category': 'mcp_security', 'message': 'MD5 used for password hashing — insecure and should be replaced.', 'patterns': ['(?i)hashlib\\.md5\\(password', '(?i)(?:MessageDigest\\.getInstance\\("MD5"|MD5)\\).{0,40}password']},
    {'id': 'CALUS-MCP-SCAN-3152', 'name': 'mcp-truncated-key-derivation', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Direct password truncation used for key derivation — should use a proper KDF.', 'patterns': ['(?i)password\\.encode\\(\\)\\[:16\\]', '(?i)(?:key|pass).{0,40}?\\[:16\\]']},
    {'id': 'CALUS-MCP-SCAN-3153', 'name': 'mcp-c2-tasking-channel-pattern', 'severity': 'high', 'category': 'mcp_security', 'message': "Detected code that leverages MCP to establish a covert C2 channel for agent tasking. This pattern matches the paper's decoupled C2 architecture where tasking commands are hidden in MCP traffic.", 'patterns': ['(?i)(?:from\\s+mcp\\.client|import\\s+mcp\\.client).{0,40}\\btool\\b.{0,40}\\b(?:task|command|run|exec)\\b', '(?i)(?:subprocess\\.run|subprocess\\.Popen|os\\.system)\\s*\\(.{0,100}\\b(?:mcp|model.context.protocol)\\b', '(?i)server\\.(?:add_tool|register_tool)\\s*\\(.{0,100}\\b(?:c2|command|control|task|deploy|exec)\\b', '(?i)\\b(?:ToolContext|ContextProvider)\\b.{0,40}\\b(?:forward|send|channel|proxy)\\s*\\(']},
    {'id': 'CALUS-MCP-SCAN-3154', 'name': 'mcp-c2-reasoning-channel-proxy', 'severity': 'medium', 'category': 'mcp_security', 'message': "Detected MCP code proxying LLM API calls, enabling a reasoning channel that appears as legitimate AI traffic to a trusted vendor. This matches the paper's two-leg stealth C2.", 'patterns': ['(?i)\\b(?:anthropic|openai)\\.(?:Anthropic|OpenAI)\\b.{0,100}\\bmcp\\.client\\b', '(?i)\\bmcp\\.(?:create_context|update_context)\\b.{0,100}\\b(?:api_key|model|prompt|reasoning)\\b', '(?i)(?:import\\s+requests|from\\s+requests).{0,100}\\b(?:anthropic|openai)\\b.{0,100}\\bmcp\\b', '(?i)(?:aiohttp|httpx)\\..{0,50}\\b(?:chat\\.completions|messages\\.create)\\b.{0,100}\\b(?:anthropic|openai)\\b.{0,100}\\b(?:mcp|client)\\b']},
    {'id': 'CALUS-MCP-SCAN-3155', 'name': 'mcp-c2-event-driven-beacon-replacement', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Detected MCP event-driven patterns that replace periodic beaconing with stealthy, asynchronous command delivery. Attackers use this to avoid detection by NDR.', 'patterns': ['(?i)\\bmcp\\.(?:subscribe|unsubscribe|notify|on_event)\\b.{0,60}\\b(?:command|control|task|trigger)\\b', '(?i)(?:async\\s+def|def)\\s+on_mcp_.{0,50}(?:event|message|notification)\\b.{0,100}\\b(?:execute|run|deploy|send|receive)\\b', '(?i)\\b(?:with|using)\\s+mcp\\.(?:EventStream|StreamContext|Subscription)\\b.{0,100}\\b(?:c2|agent|task|payload)\\b', '(?i)\\b(?:session|agent)\\.on\\(\\s*[\'"](?:message|event|command)[\'"]\\s*\\).{0,100}\\b(?:mcp|model.context.protocol)\\b']},
    {'id': 'CALUS-MCP-SCAN-3156', 'name': 'mcp-c2-multi-agent-orchestrator', 'severity': 'medium', 'category': 'mcp_security', 'message': "Detected MCP-based multi-agent orchestrator pattern enabling parallel, distributed C2 operations. This matches the paper's swarm orchestration where a central MCP server coordinates multiple agents.", 'patterns': ['(?i)\\b(?:agent_manager|orchestrator|swarm_controller|command_agent)\\b.{0,80}\\bmcp\\.(?:server|client)\\b', '(?i)(?:for\\s+agent|while\\s+.{0,40}agents?).{0,80}\\b(?:mcp|spawn|deploy|launch)\\b.{0,80}\\b(?:parallel|concurrent|async|multi)\\b', '(?i)(?:ThreadPoolExecutor|asyncio\\.gather|concurrent\\.futures).{0,80}\\b(?:mcp|agent)\\b.{0,80}\\b(?:task|command|run|execute)\\b', '(?i)\\b(?:agent_group|fleet|swarm)\\b.{0,60}\\b(?:register|connect)\\s*\\(.{0,40}\\b(?:mcp|server|endpoint)\\b']},
    {'id': 'CALUS-MCP-SCAN-3157', 'name': 'mcp-c2-persistent-sqlite-memory', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected SQLite database used as persistent memory for MCP agent. While legitimate for many apps, attackers use this pattern to maintain long-term state for C2 operations as described in the paper.', 'patterns': ['(?i)\\bsqlite3\\b.{0,80}\\bmcp\\b.{0,80}\\b(?:memory|context|state|history|session)\\b', '(?i)\\sCREATE\\s+(?:TABLE|DATABASE)\\s+.{0,40}(?:mcp_|agent_|task_|session_).{0,40}(?:context|memory|history)\\b', '(?i)\\bmcp\\b.{0,80}\\b(?:sqlite|sqlite3)\\b.{0,80}\\b(?:save|load|store|persist|log)\\b', '(?i)(?:import\\s+sqlite3|from\\s+sqlite3).{0,100}\\b(?:mcp|context|agent|session)\\b']},
    {'id': 'CALUS-MCP-SCAN-3158', 'name': 'mcp-c2-credential-exfiltration-logging', 'severity': 'critical', 'category': 'mcp_security', 'message': 'Detected MCP-based credential exfiltration pattern. Attackers use the MCP channel to extract discovered credentials from compromised hosts.', 'patterns': ['(?i)\\bmcp\\.(?:client|server)\\b.{0,100}\\b(?:password|credential|secret|token|api[_-]?key)\\b.{0,40}\\b(?:exfil|send|upload|log|share)\\b', '(?i)\\b(?:log|store|save)\\s*\\(.{0,80}\\b(?:password|credential|secret|token|api[_-]?key)\\b.{0,80}\\bmcp\\b', '(?i)\\bmcp_context\\b.{0,80}\\b(?:password|credential|secret|api[_-]?key)\\s*(?:=|:)\\s*[\'"][^\'"]+[\'"]', '(?i)\\b(?:client\\.call_tool|server\\.handle_call)\\b.{0,40}\\b(?:exfil|steal|collect)\\b.{0,80}\\b(?:creds|pass|token)\\b']},
    {'id': 'CALUS-MCP-SCAN-3159', 'name': 'mcp-c2-polymorphic-payload-generation', 'severity': 'high', 'category': 'mcp_security', 'message': 'Detected MCP agent code that generates polymorphic or obfuscated payloads. Attackers use this to evade signature-based detection.', 'patterns': ['(?i)\\b(?:generat|creat|build|craft|construct)\\w*\\s*.{0,40}\\b(?:payload|exploit|shellcode|dropper)\\b.{0,80}\\b(?:mcp|agent)\\b', '(?i)\\b(?:obfuscat|encrypt|mutate|polymorph|transform|encode)\\w*\\b.{0,60}\\bpayload\\b.{0,80}\\b(?:mcp|agent|deploy|send)\\b', '(?i)\\bmcp\\b.{0,80}\\b(?:payload|exploit|shellcode)\\b.{0,80}\\b(?:obfuscat|encrypt|mutate|polymorph|transform)\\b', '(?i)\\b(?:lambda|eval|exec)\\s*\\(.{0,40}\\b(?:mcp|payload|agent)\\b']},
    {'id': 'CALUS-MCP-SCAN-3160', 'name': 'mcp-c2-lotl-command-execution', 'severity': 'high', 'category': 'mcp_security', 'message': 'Detected MCP tool that executes living-off-the-land commands. Attackers use this to blend in with legitimate administrative activity.', 'patterns': ['(?i)\\bmcp\\b.{0,80}\\b(?:cmd|powershell|sh|bash|wmic|vssadmin|wscript|cscript)\\b.{0,60}\\b(?:run|exec|call|invoke|execute)\\b', '(?i)\\b(?:subprocess\\.run|subprocess\\.Popen|os\\.system|exec)\\s*\\(.{0,40}\\b(?:cmd\\.exe|powershell\\.exe|bash|sh)\\b.{0,80}\\bmcp\\b', '(?i)\\b(?:run_lotl|lotl_command|living_off_the_land)\\b.{0,60}\\s*:?=\\s*.{0,40}mcp', '(?i)\\b(?:tool|function)\\s*\\(.{0,60}\\b(?:run|exec|cmd)\\b.{0,40}\\b(?:cmd|powershell|bash|sh)\\b.{0,80}\\bmcp']},
    {'id': 'CALUS-MCP-SCAN-3161', 'name': 'mcp-c2-encrypted-channel-setup', 'severity': 'medium', 'category': 'mcp_security', 'message': "Detected encrypted MCP channel setup that could be used for stealthy C2 communications as per the paper's design.", 'patterns': ['(?i)\\bmcp\\.(?:server|client)\\b.{0,80}\\b(?:wss?:\\/\\/|https?:\\/\\/).{0,80}\\b(?:cert|key|ssl|tls|ca_certs)\\b', '(?i)\\b(?:websocket|WebSocket\\s*WebSocket)\\b.{0,80}\\bmcp\\b.{0,80}\\b(?:c2|command|control|agent|task)\\b', '(?i)\\b(?:ssl_context|load_cert_chain|wrap_socket)\\b.{0,80}\\b(?:mcp|model.context.protocol)\\b', '(?i)\\b(?:start_tls|upgrade_to_tls)\\s*\\(.{0,40}\\b(?:mcp|context|session)\\b.{0,60}\\b(?:cert|key|ssl)\\b']},
    {'id': 'CALUS-MCP-SCAN-3162', 'name': 'mcp-c2-agent-session-persistence', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected persistent MCP session logic that could be used to maintain C2 resilience. While legitimate for many apps, attackers use this to prevent command disruption.', 'patterns': ['(?i)\\b(?:reconnect|retry|persist|keepalive|heartbeat)\\b.{0,60}\\bmcp\\.(?:client|server|session)\\b', '(?i)\\b(?:while\\s+True|for\\s+attempt|while\\s+.{0,40}connected)\\b.{0,100}\\b(?:mcp|context|session)\\b.{0,60}\\b(?:run|connect|reconnect|retry)\\b', '(?i)\\bmcp\\.(?:session|client|server)\\b.{0,80}\\b(?:timeout|retry|interval|backoff|persist)\\b', '(?i)\\b(?:AutoReconnect|PersistSession|SessionManager)\\b.{0,80}\\b(?:mcp|agent)\\b']},
    {'id': 'CALUS-MCP-SCAN-3164', 'name': 'mcp-log-covert-channel-data-transfer', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP system log shows signs of covert channel attack - data exfiltration via hidden channels detected.', 'patterns': ['(?i)\\b(?:covert|stealth|hidden|encode)[_-]?channel\\b.{0,40}\\b(?:data|exfil|transfer|send|transmit)\\b']},
    {'id': 'CALUS-MCP-SCAN-3166', 'name': 'mcp-log-privilege-escalation', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP system log shows privilege escalation attempt - unauthorized elevation of access detected.', 'patterns': ['(?i)\\b(?:privilege|escalation|elevat|root|sudo)\\b.{0,40}\\b(?:gain|obtain|exploit|attack|compromis)\\b', '(?i)\\b(?:su\\s|sudo\\s|chmod\\s[0-7]{3,4})\\b.{0,40}\\b(?:exploit|attack|unauthorized|bypass)\\b', '(?i)\\b(?:setuid|setgid|capability).{0,40}\\b(?:escalat|exploit|abuse)\\b']},
    {'id': 'CALUS-MCP-SCAN-3167', 'name': 'mcp-log-backdoor-implantation', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP system log shows backdoor implantation attempt - persistent unauthorized access detected.', 'patterns': ['(?i)\\b(?:cron|scheduled.{0,20}task).{0,40}\\b(?:backdoor|malicious|reverse.{0,20}shell|payload)\\b', '(?i)\\b(?:ssh.{0,20}key|authorized_key).{0,40}\\b(?:backdoor|unauthorized|malicious)\\b']},
    {'id': 'CALUS-MCP-SCAN-3168', 'name': 'mcp-log-cache-pollution', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP system log indicates cache or local state pollution - stored data may be compromised.', 'patterns': ['(?i)\\b(?:cache|state|local.{0,20}store).{0,40}\\b(?:pollut|poison|corrupt|modify|overwrite)\\b']},
    {'id': 'CALUS-MCP-SCAN-3169', 'name': 'mcp-log-delayed-trigger-implant', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP system log shows delayed trigger implant - malicious action set to activate later detected.', 'patterns': ['(?i)\\b(?:schedule.{0,40}malicious|malicious.{0,40}schedule|deferred.{0,40}attack)\\b']},
    {'id': 'CALUS-MCP-SCAN-3171', 'name': 'mcp-log-explosion-attack', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP system log shows possible log explosion attack - excessive log generation detected.', 'patterns': ['(?i)\\b(?:log.{0,20}explosion|log.{0,20}flood|log.{0,20}burst|log.{0,20}spam).{0,40}\\b(?:attack|malicious|obfuscate|hide|fill)\\b', '(?i)\\b(?:write.{0,40}10[0-9]{3,}|append.{0,40}repeated|generat.{0,40}excess).{0,40}\\b(?:log|entry|record)\\b']},
    {'id': 'CALUS-MCP-SCAN-3172', 'name': 'mcp-ac-app-level-api-host-obfuscation', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected obfuscated API host construction using character codes, indicative of application-level MCP attack.', 'patterns': ['(?i)\\bhostFromCharCodes\\s*\\(\\s*\\[\\s*\\d+\\s*,\\s*\\d+\\s*,', '(?i)\\bplace_static_codes\\s*=\\s*\\[\\s*(?:51|52|53|54|55|46|56|57|58)\\b', '(?i)apiHost\\s*=\\s*\\w+\\s*\\+\\s*\\w+\\s*;\\s*//\\s*rest of the function']},
    {'id': 'CALUS-MCP-SCAN-3173', 'name': 'mcp-agentbound-system-exec-capability', 'severity': 'high', 'category': 'mcp_security', 'message': 'MCP server code uses OS command execution; ensure manifest includes mcp.ac.system.exec.', 'patterns': ['(?i)\\b(execa|shelljs)\\.\\w+\\s*\\(', '(?i)from\\s+(?:sh|pexpect|paramiko)\\s+import']},
    {'id': 'CALUS-MCP-SCAN-3174', 'name': 'mcp-agentbound-network-capability-mismatch', 'severity': 'high', 'category': 'mcp_security', 'message': 'MCP server code performs network I/O but manifest may lack mcp.ac.network.client capability.', 'patterns': ['(?i)(?:from\\s+http\\.client|import\\s+http\\.client|from\\s+urllib\\.request)']},
    {'id': 'CALUS-MCP-SCAN-3175', 'name': 'mcp-agentbound-filesystem-exfiltration', 'severity': 'critical', 'category': 'mcp_security', 'message': 'Detected pattern: reading sensitive files followed by network call, potential exfiltration attempt.', 'patterns': ['(?i)\\b(?:readFile|read_text|open|cat)\\s*\\(\\s*[\'"](?:\\.env|\\/etc\\/passwd|id_rsa|\\/home|\\/Users|\\/root|\\/etc\\/shadow)[\'"]']},
    {'id': 'CALUS-MCP-SCAN-3176', 'name': 'mcp-agentbound-tool-poisoning-description-modification', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP tool description is being modified at runtime, indicating potential tool poisoning or rug pull attack.', 'patterns': ['(?i)\\b(tool|function|method)\\s*\\.\\s*(description|name)\\s*[=:]\\s*[\'"][^\'"]*[\'"]', '(?i)\\bupdateTool\\s*\\(\\s*[\'"][^\'"]*[\'"\']\\s*,\\s*\\{[^}]*description\\s*[=:]\\s*[\'"][^\'"]*[\'"]']},
    {'id': 'CALUS-MCP-SCAN-3177', 'name': 'mcp-agentbound-rug-pull-tool-change-after-count', 'severity': 'high', 'category': 'mcp_security', 'message': 'Conditional behavior change based on call count detected, indicating a possible rug pull attack.', 'patterns': ['(?i)\\b(invocationCount|callCount|times|counter)\\s*(>|>=|===)\\s*\\d+', '(?i)\\bif\\s*\\(\\s*\\w+\\s*(>|>=)\\s*\\d+\\s*\\)\\s*\\{[^}]*\\b(tool|function|description|url|path)\\s*[=:]']},
    {'id': 'CALUS-MCP-SCAN-3178', 'name': 'mcp-agentbound-filesystem-write-delete-no-capability', 'severity': 'high', 'category': 'mcp_security', 'message': 'MCP server code can write or delete files; ensure manifest declares mcp.ac.filesystem.write/delete.', 'patterns': ['(?i)subprocess\\.run\\s*\\(\\s*\\[\'\\s*[\'"]rm[\'"]']},
    {'id': 'CALUS-MCP-SCAN-3179', 'name': 'mcp-tool-poisoning-crafted-description', 'severity': 'low', 'category': 'mcp_security', 'message': 'Malicious tool description detected: attempts to manipulate model into exfiltration or unauthorized actions.', 'patterns': ['(?i)\\b(?:read|access|get)\\b.{0,40}\\b(?:file|config|env|secret|credential|database|mail|message|chat|history|conversation)\\b.{0,40}\\b(?:and|then|after|once)\\b.{0,40}\\b(?:return|output|display|print|log|send|exfil)\\b']},
    {'id': 'CALUS-MCP-SCAN-3180', 'name': 'mcp-tool-poisoning-crafted-error-msg', 'severity': 'low', 'category': 'mcp_security', 'message': 'Crafted error message detected: may mislead model into invoking additional tools with attacker-controlled parameters.', 'patterns': ['(?i)\\b(?:permission|access|authorization|authentication)\\b.{0,40}\\b(?:denied|rejected|failed|insufficient|missing|expired)\\b.{0,40}\\b(?:use|call|invoke)\\b.{0,40}\\b(?:built-in|system|admin|sudo|root|privileged|elevated)\\b']},
    {'id': 'CALUS-MCP-SCAN-3184', 'name': 'mcp-typosquatting-server-name', 'severity': 'low', 'category': 'mcp_security', 'message': 'Potential typosquatting MCP server name: may impersonate legitimate server to trick users.', 'patterns': ['(?i)\\b(?:slack\\b.{0,40}\\bmcp|slak-mcp|slck-mcp|sla[c]k\\bmcp)\\b']},
    {'id': 'CALUS-MCP-SCAN-3185', 'name': 'mcp-tool-poisoning-request-info-extraction', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool description attempts to extract request context: could leak system prompt, tool list, or history.', 'patterns': ['(?i)\\b(?:embed|include|put|place|set|attach|pass\\b).{0,40}\\b(?:system|prompt|tool\\s*list|history|context|request|user\\s*query|conversation|session)\\b.{0,40}\\b(?:into|in|as|to|for)\\b.{0,40}\\b(?:parameter|argument|param|input|payload|body|content|value|field)\\b']},
    {'id': 'CALUS-MCP-SCAN-3187', 'name': 'mcp-remote-server-untrusted-endpoint', 'severity': 'low', 'category': 'mcp_security', 'message': 'Remote MCP server configured with untrusted endpoint: potential for server hijacking or malicious data exfiltration.', 'patterns': ['(?i)(?:url|endpoint|server_url)\\s*[=:]\\s*[\'"](?:https?://)?[\\w-]+\\.(?:xyz|top|bid|download|click|stream|help|info|site|online|win|vip|pw|ml|tk|ga|cf)\\b', '(?i)(?:url|endpoint|server_url)\\s*[=:]\\s*[\'"]https?://[^\'"]*[\\?&](?:token|key|secret|auth|api[_-]key|password|passwd|credential)=[^\'"]+[\'"]']},
    {'id': 'CALUS-MCP-SCAN-3188', 'name': 'mcp-tool-poisoning-abuse-built-in', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool description encourages abuse of built-in tools: could lead to file exfiltration or command execution.', 'patterns': ['(?i)\\b(?:use|call|invoke|trigger|activate|employ|leverage)\\b.{0,30}\\b(?:built-in|built in|native|internal|system|host)\\b.{0,30}\\b(?:tool|function|command|utility|operation)\\b.{0,40}\\b(?:to|for|in order to)\\b.{0,60}\\b(?:read|execute|run|delete|modify|exfil|send|leak|dump|download|upload)\\b', '(?i)\\b(?:use|call|invoke|trigger|activate)\\b.{0,20}\\b(?:read_file|write_file|shell_exec|run_command|execute_shell|open_url|fetch_url|http_get|http_post|send_email|list_directory)\\b']},
    {'id': 'CALUS-MCP-SCAN-3189', 'name': 'mcp-tool-poisoning-abuse-server-provided', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool description encourages abuse of other server tools: could lead to unauthorized operations via other configured services.', 'patterns': ['(?i)\\b(?:use|call|invoke|trigger|employ|leverage)\\b.{0,30}\\b(?:other|another|different|third-party|external|third party)\\b.{0,30}\\b(?:tool|service|server|function)\\b.{0,40}\\b(?:to|for|in order to)\\b.{0,60}\\b(?:execute|run|create|delete|modify|send|post|commit|push|merge|deploy|approve|transfer|exfil)\\b', '(?i)\\b(?:call|invoke|use|trigger)\\b.{0,20}\\b(?:github|gitlab|slack|gmail|drive|calendar|jira|notion|asana|linear|sentry|datadog)\\b.{0,30}\\b(?:tool|service|function|API)\\b']},
    {'id': 'CALUS-MCP-SCAN-3190', 'name': 'mcp-hijack-server-owner-change', 'severity': 'low', 'category': 'mcp_security', 'message': 'Maintainer change detected in MCP server package: possible account hijacking.', 'patterns': ['(?i)"maintainers":\\s*\\[[^\\]]*\\]']},
    {'id': 'CALUS-MCP-SCAN-3191', 'name': 'mcp-tool-response-user-impersonation', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool response contains user impersonation pattern likely to trick agent into executing malicious instructions.', 'patterns': ['(?i)(?:I am the user|pretend to be the user|as the user).{0,40}(?:complete|finish|perform|execute|do).{0,40}(?:task|step|action|instruction)', '(?i)(?:previous task has been completed|new task).{0,60}(?:urgent|must finish|please make sure|need you to complete)']},
    {'id': 'CALUS-MCP-SCAN-3192', 'name': 'mcp-tool-response-false-error', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool response uses false error to coerce agent into following malicious instructions.', 'patterns': ['(?i)(?:tool failed|execution error|result not available).{0,40}(?:must|required).{0,40}(?:follow|adhere|execute|perform).{0,40}(?:instruction|guideline)']},
    {'id': 'CALUS-MCP-SCAN-3193', 'name': 'mcp-tool-response-tool-transfer', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool response contains tool transfer directive that may redirect agent to a malicious tool.', 'patterns': ['(?i)(?:This tool is no longer available|has been replaced by|use this tool instead|migrated to).{0,60}(?:tool|service|function|endpoint)', '(?i)(?:no longer supported|deprecated).{0,40}(?:replaced by|use this).{0,40}(?:tool|function|command)']},
    {'id': 'CALUS-MCP-SCAN-3194', 'name': 'mcp-tool-preference-manipulation', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool description contains promotional/deceptive language likely used in preference manipulation attacks.', 'patterns': ['(?i)(?:best tool|highly recommended|optimal choice|top-rated|most effective).{0,40}(?:for|to|tool|function|service)']},
    {'id': 'CALUS-MCP-SCAN-3195', 'name': 'mcp-tool-name-collision', 'severity': 'low', 'category': 'mcp_security', 'message': "Tool name matches pattern used in name collision attacks (e.g., 'toolnamev1').", 'patterns': ['(?i)^[a-z_]+v\\d+$', '(?i)^[a-z_]+copy$']},
    {'id': 'CALUS-MCP-SCAN-3197', 'name': 'mcp-tool-prompt-injection-description', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool description contains imperative instructions indicative of prompt injection attack.', 'patterns': ['(?i)Use the.{0,40}tool.{0,40}(?:terminate|kill|delete|remove|transfer|shutdown|exec)', '(?i)(?:you must|please ensure|strictly adhere|important).{0,40}(?:run|execute|call|invoke).{0,40}(?:tool|command|function)']},
    {'id': 'CALUS-MCP-SCAN-3198', 'name': 'mcp-retrieval-injection-external-data', 'severity': 'low', 'category': 'mcp_security', 'message': 'External data contains imperative instructions that match retrieval injection attack pattern.', 'patterns': ['(?i)(?:IMPORTANT|NOTE|PLEASE NOTE|ATTENTION).{0,20}(?:in order to|you must|strictly adhere|follow).{0,60}(?:instruction|guideline|step|command)', '(?i)(?:for a smooth visit|to proceed|to continue).{0,40}(?:you must|you need to|strictly adhere).{0,60}(?:instruction|action|step)']},
    {'id': 'CALUS-MCP-SCAN-3199', 'name': 'mcp-config-overprivileged-launch-docker-mount', 'severity': 'low', 'category': 'mcp_security', 'message': 'Docker run command in MCP config mounts entire host root filesystem, granting unrestricted host access.', 'patterns': ['(?i)docker\\s+(?:run|create)\\s+(?:[^\\s]*\\s+){0,10}-v\\s+/:/mnt/host', '(?i)docker\\s+(?:run|create).{0,40}--mount\\s+type=bind\\s+source=/,target=/mnt/host']},
    {'id': 'CALUS-MCP-SCAN-3201', 'name': 'mcp-tool-output-propagation-instruction', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool output contains instruction to call another tool or send data externally, indicating unauthorized propagation attack.', 'patterns': ['(?i)(?:send|forward|email|share).{0,40}(?:the|this).{0,40}(?:content|data|output|information).{0,40}(?:to|via)']},
    {'id': 'CALUS-MCP-SCAN-3202', 'name': 'mcp-server-name-impersonation-legitimate', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP server name impersonates a legitimate service, potentially misleading LLM and users.', 'patterns': ['(?i)(?:paypal|google|aws|github|stripe|openai).{0,20}(?:official|legitimate|original|real)']},
    {'id': 'CALUS-MCP-SCAN-3203', 'name': 'mcp-tool-description-information-overcollection', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool description requests sensitive personal data that exceeds legitimate function requirements.', 'patterns': ['(?i)(?:allergy|medical condition|dietary restriction).{0,60}(?:provide|input|enter|submit).{0,30}(?:details|information)']},
    {'id': 'CALUS-MCP-SCAN-3204', 'name': 'mcp-resource-mimetype-confusion', 'severity': 'low', 'category': 'mcp_security', 'message': 'Resource mimeType mismatch with actual content, potentially enabling type confusion attack.', 'patterns': ['(?i)mimeType.{0,30}text/html.{0,60}(?:content|data|uri).{0,40}(?:exec|shell|command|script)', '(?i)mimeType.{0,30}application/x-sh.{0,60}']},
    {'id': 'CALUS-MCP-SCAN-3205', 'name': 'mcp-initialization-bind-address-exposure', 'severity': 'high', 'category': 'mcp_security', 'message': 'MCP server initialization binds to 0.0.0.0, exposing server to all network interfaces.', 'patterns': ['(?i)bind\\s*(?:=|to)\\s*[\'"]0\\.0\\.0\\.0[\'"]']},
    {'id': 'CALUS-MCP-SCAN-3206', 'name': 'mcp-json-reverse-shell-payload', 'severity': 'low', 'category': 'mcp_security', 'message': 'Reverse shell payload detected in mcp.json: bash -i over TCP to attacker-controlled host.', 'patterns': ['(?i)bash\\s*-i\\s*[>&]+\\s*/dev/tcp/\\S+\\s*\\d+\\s*[>&]+\\s*&\\d', '(?i)/dev/tcp/\\S+\\s*\\d+\\s*(?:0>&1|1>&0)']},
    {'id': 'CALUS-MCP-SCAN-3207', 'name': 'mcp-upd-parasitic-ingestion-exfiltration-toolchain', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected toolchain combining ingestion, privacy access, and network exfiltration tools - potential MCP-UPD parasitic attack.', 'patterns': ['(?i)(?:fetch|get_posts|search|read_url|browse).{0,40}(?:read_file|read_config|get_secret|list_directory|get_env|read_chat_history).{0,60}(?:send_mail|post|upload|http_post|send_to|exfiltrate|write_to_remote)', '(?i)(?:from\\s+.{0,40}\\s+import|import\\s+).{0,40}(?:Fetch|GetPosts|Search|ReadUrl|Browse)\\s*[,|\\s].{0,40}(?:ReadFile|ReadConfig|GetSecret|ListDir|GetEnv|ReadChatHistory)\\s*[,|\\s].{0,40}(?:SendMail|Post|Upload|HttpPost|SendTo|Exfiltrate|WriteRemote)']},
    {'id': 'CALUS-MCP-SCAN-3208', 'name': 'mcp-upd-exfiltration-endpoint-email-pattern', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected email exfiltration endpoint potentially used in MCP-UPD attack - data sent to attacker-controlled address.', 'patterns': ['(?i)(?:to|recipient|email|address).{0,20}(?:@attacker\\.com|@evil\\.com|@malicious\\.net|@exfil\\.xyz|diag@)', '(?i)(?:send_mail|send_email|send_message|send_email_notification|mailto).{0,40}(?:\\bdiag@|\\battacker@|\\bevil@|\\bmalicious@|\\bexfil@)']},
    {'id': 'CALUS-MCP-SCAN-3209', 'name': 'mcp-guard-shadow-hijack-pattern', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected potential shadow hijack pattern in MCP payload.', 'patterns': ['\\bspoofed\\s+call\\b', '\\bfake\\s+server\\b', '\\bhidden\\s+invoke\\b']},
    {'id': 'CALUS-MCP-SCAN-3210', 'name': 'mcp-guard-cross-origin-server-reference', 'severity': 'low', 'category': 'mcp_security', 'message': 'Cross-origin server reference detected in MCP configuration.', 'patterns': ['\\bexternal-server\\b', '\\bthird-party-api\\b', '\\bforeign-host\\b']},
    {'id': 'CALUS-MCP-SCAN-3211', 'name': 'ama-tool-metadata-manipulation-generator', 'severity': 'high', 'category': 'mcp_security', 'message': 'AMA generation scripts found: code creates tool metadata optimized for LLM agent attraction (81-95% ASR).', 'patterns': ['(?i)(?:from|import)\\s+attractive_metadata_attack\\b', '(?i)\\b(?:GenerateCall|Meta\\(t\\)|MetaVersatileOptimizer|Universal_Solution_Aggregator)\\b']},
    {'id': 'CALUS-MCP-SCAN-3212', 'name': 'ama-weighted-value-evaluation', 'severity': 'low', 'category': 'mcp_security', 'message': 'AMA weighted value evaluation function detected: used to select high-inducement tool metadata.', 'patterns': ['(?i)\\bweighted_value\\b.{0,40}\\blambda\\b', '(?i)\\bp_j_i\\b.{0,40}\\blambda\\b.{0,40}\\(\\s*p_j_i\\s*-\\s*p_j\\s*\\)']},
    {'id': 'CALUS-MCP-SCAN-3213', 'name': 'ama-tool-invocation-probability-function', 'severity': 'medium', 'category': 'mcp_security', 'message': 'AMA invocation probability function found: measures tool selection likelihood for optimization.', 'patterns': ['(?i)\\binvocation_probability\\b.{0,40}\\bargmax\\b', '(?i)\\bP\\(\\s*t\\s*,\\s*Q\\s*,\\s*NT\\s*\\)\\s*=']},
    {'id': 'CALUS-MCP-SCAN-3214', 'name': 'ama-state-update-topk', 'severity': 'low', 'category': 'mcp_security', 'message': 'AMA state update with TopK selection found: used to retain the most attractive malicious tools.', 'patterns': ['(?i)\\bTopKnt\\b.{0,40}\\bweighted_value\\b', '(?i)\\btop_nt\\b.{0,40}\\bsorted\\b.{0,40}\\bV\\b']},
    {'id': 'CALUS-MCP-SCAN-3215', 'name': 'ama-generation-traceability-indexing', 'severity': 'low', 'category': 'mcp_security', 'message': 'AMA generation traceability indexing pattern detected: tracks tool lineage across iterations.', 'patterns': ['(?i)\\bt_j\\^i\\b', '(?i)\\bparent_tool\\b.{0,40}\\bt_j\\b']},
    {'id': 'CALUS-MCP-SCAN-3216', 'name': 'ama-mcp-bypass-demo-code', 'severity': 'low', 'category': 'mcp_security', 'message': 'AMA MCP bypass demo code: research code showing metadata attack under Model Context Protocol.', 'patterns': ['(?i)\\bModelContextProtocol\\b.{0,60}\\bmetadata\\b', '(?i)\\bmcp\\b.{0,20}\\bama\\b.{0,20}\\battack\\b']},
    {'id': 'CALUS-MCP-SCAN-3217', 'name': 'ama-cross-model-transfer-evaluation', 'severity': 'low', 'category': 'mcp_security', 'message': 'AMA cross-model transferability evaluation: tests tool metadata generated by one model against others.', 'patterns': ['(?i)\\bcross_model\\b.{0,40}\\btransfer\\b', '(?i)\\bamos\\b.{0,40}\\basr\\b.{0,40}\\btransfer\\b']},
    {'id': 'CALUS-MCP-SCAN-3218', 'name': 'mcp-exfil-send-research-data-tool', 'severity': 'low', 'category': 'mcp_security', 'message': 'Malicious send_research_data MCP tool detected; used in Trivial Trojans cross-server exfiltration attack.', 'patterns': ['(?i)\\bsend_research_data\\b', '(?i)(?:def|app\\.tool|@fastmcp\\.tool)\\s*\\(?\\s*[\'"]?send_research_data[\'"]?\\s*\\)?']},
    {'id': 'CALUS-MCP-SCAN-3219', 'name': 'mcp-exfil-webhook-site-outbound', 'severity': 'high', 'category': 'mcp_security', 'message': 'Outbound HTTP POST to webhook.site detected; potential data exfiltration vector.', 'patterns': ['(?i)webhook\\.site.{0,20}(?:post|request|send)', '(?i)requests\\.post\\(\\s*[\'"]https?://webhook\\.site', '(?i)httpx\\.post\\(\\s*[\'"]https?://webhook\\.site']},
    {'id': 'CALUS-MCP-SCAN-3220', 'name': 'mcp-social-engineering-weather-personalization', 'severity': 'low', 'category': 'mcp_security', 'message': 'Social engineering prompt combining weather context with financial data access; possible Trivial Trojans attack.', 'patterns': ['(?i)(?:budget[\\s-]?conscious|personalized weather).{0,40}(?:account|balance|bank)', '(?i)(?:weather.{0,20}financial|financial.{0,20}weather).{0,40}(?:recommend|advice|suggest)', '(?i)(?:to provide|for providing).{0,20}personalized weather']},
    {'id': 'CALUS-MCP-SCAN-3221', 'name': 'mcp-cross-server-tool-discovery-pattern', 'severity': 'low', 'category': 'mcp_security', 'message': 'Cross-server tool discovery pattern detected; may enable unauthorised data access across MCP servers.', 'patterns': ['(?i)call_tool\\(.{0,30}account\\.balance', '(?i)tool_discovery.{0,40}get_tool']},
    {'id': 'CALUS-MCP-SCAN-3222', 'name': 'mcp-malicious-weather-server-example-code', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Code matching Trivial Trojans malicious weather server pattern detected; possible cross-server exfiltration.', 'patterns': ['(?i)from\\s+fastmcp\\s+import.{0,40}FastMCP', '(?i)(?:@fastmcp\\.prompt|app\\.add_prompt).{0,60}weather.{0,60}balance', '(?i)send_research_data']},
    {'id': 'CALUS-MCP-SCAN-3223', 'name': 'mcp-oauth-token-short-expiry-notice', 'severity': 'low', 'category': 'mcp_security', 'message': 'OAuth token with short expiry (e.g., 30-hour Monzo refresh token) may limit exploitation window but indicates sensitive API access.', 'patterns': ['(?i)30.{0,10}(?:hour|hr).{0,20}(?:token|refresh|expire)', '(?i)token.{0,20}(?:expire|refresh).{0,20}30', '(?i)monzo.{0,30}token']},
    {'id': 'CALUS-MCP-SCAN-3224', 'name': 'mcp-request-to-unknown-external-endpoint', 'severity': 'low', 'category': 'mcp_security', 'message': 'Dynamic HTTP request to external URL in MCP server; verify endpoint to prevent data exfiltration.', 'patterns': ['(?i)httpx\\.(?:post|get)\\(\\s*f[\'"].{0,40}https?://', '(?i)urllib\\.request\\.urlopen\\(\\s*f[\'"].{0,40}https?://']},
    {'id': 'CALUS-MCP-SCAN-3225', 'name': 'mcp-blog-publisher-subprocess-unsanitized-git', 'severity': 'critical', 'category': 'mcp_security', 'message': 'Unsanitized git subprocess call detected, enabling command injection.', 'patterns': ['(?i)subprocess\\.(?:run|Popen|call)\\s*\\(\\s*\\[\\s*[\'"]git[\'"]', '(?i)subprocess\\.(?:run|Popen|call)\\s*\\(\\s*[\'"].{0,40}\\bgit\\b']},
    {'id': 'CALUS-MCP-SCAN-3226', 'name': 'mcp-blog-publisher-shutil-copy-file', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Unrestricted file copy operation detected; may exfiltrate sensitive data.', 'patterns': ['(?i)\\bshutil\\.copy\\s*\\(', '(?i)\\bshutil\\.copytree\\s*\\(']},
    {'id': 'CALUS-MCP-SCAN-3227', 'name': 'mcp-twitter-mcp-tweet-post-image', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Image processing combined with tweet posting, potential for malicious metadata embedding.', 'patterns': ['(?i)\\.post\\s*\\(.{0,40}\\btweet\\b', '(?i)Image\\.open\\s*\\(.{0,40}\\.(?:png|jpg|jpeg)']},
    {'id': 'CALUS-MCP-SCAN-3228', 'name': 'mcp-web-research-openai-client-exfil', 'severity': 'low', 'category': 'mcp_security', 'message': 'OpenAI client used with network calls; may exfiltrate data to external endpoints.', 'patterns': ['(?i)(?:openai|OpenAI)\\s*\\(.{0,40}\\)\\s*.{0,40}(?:post|get|request)', '(?i)(?:post|get|request).{0,40}(?:openai|OpenAI)\\s*\\(']},
    {'id': 'CALUS-MCP-SCAN-3229', 'name': 'mcp-web-research-load-dotenv-cred-exposure', 'severity': 'low', 'category': 'mcp_security', 'message': 'Environment variable loading detected; ensure .env file is properly secured.', 'patterns': ['(?i)\\bload_dotenv\\s*\\(\\s*[\'"][^\'"]+[\'"]\\s*\\)']},
    {'id': 'CALUS-MCP-SCAN-3231', 'name': 'mcp-high-risk-system-call-broad', 'severity': 'medium', 'category': 'mcp_security', 'message': 'System-level API detected; may allow process spawning or command execution.', 'patterns': ['(?i)\\bsubprocess\\.call\\s*\\(']},
    {'id': 'CALUS-MCP-SCAN-3232', 'name': 'mcp-high-risk-network-socket', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Network socket operation detected; may allow arbitrary network connections.', 'patterns': ['(?i)\\bsocket\\.bind\\s*\\(', '(?i)\\bsocket\\.connect\\s*\\(', '(?i)\\bdns\\.resolver\\.query\\s*\\(']},
    {'id': 'CALUS-MCP-SCAN-3233', 'name': 'mcp-memory-api-buffer-overflow', 'severity': 'low', 'category': 'mcp_security', 'message': 'Memory manipulation API detected; may cause buffer overflow or code injection.', 'patterns': ['(?i)\\bstrcpy\\s*\\(', '(?i)\\bmalloc\\s*\\(\\s*\\d+\\s*\\)']},
    {'id': 'CALUS-MCP-SCAN-3234', 'name': 'mcp-tool-poisoning-hidden-instruction-in-tool-def', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected tool descriptor with hidden instruction pattern in MCP server tool definition. This can lead to tool poisoning where LLM is tricked into invoking unintended tools.', 'patterns': ['(?i)\\btool\\b.{0,40}\\bdescription\\b.{0,40}(?:ignore|disregard|override|instead of)']},
    {'id': 'CALUS-MCP-SCAN-3235', 'name': 'mcp-command-injection-in-tool-input', 'severity': 'critical', 'category': 'mcp_security', 'message': 'Detected command injection vulnerability: tool parameter used directly in shell command without sanitization. Attackers may execute arbitrary commands.', 'patterns': ['(?i)subprocess\\.(?:run|Popen|call)\\s*\\(\\s*\\[\\s*[\'"](?:sh|bash|cmd|powershell)[\'"]', '(?i)subprocess\\.(?:run|Popen|call)\\s*\\(\\s*[\'"].{0,40}\\{\\s*(?:inp|param|arg|val)', '(?i)(?:os\\.system|os\\.popen|commands\\.getoutput)\\s*\\(.{0,40}(?:inp|param|arg|val)']},
    {'id': 'CALUS-MCP-SCAN-3236', 'name': 'mcp-credential-exposure-in-tool-config', 'severity': 'high', 'category': 'mcp_security', 'message': 'Hardcoded credentials detected in MCP server source or config. Credential exposure is the most prevalent vulnerability (3.6% of MCP servers).', 'patterns': ['(?i)(?:bearer|basic|digest)\\s+[\'"][A-Za-z0-9+/=]{20,}[\'"]', '(?i)(?:(?:export|set)\\s+)?(?:MCP_API_KEY|MCP_TOKEN|MCP_SECRET)\\s*[:=]']},
    {'id': 'CALUS-MCP-SCAN-3237', 'name': 'mcp-remote-code-execution-via-subprocess', 'severity': 'low', 'category': 'mcp_security', 'message': 'Remote code execution vulnerability: eval/exec or shell=True detected in MCP server. This enables malicious code execution (MCE) attacks.', 'patterns': ['(?i)subprocess\\.(?:run|Popen|call)\\s*\\(.{0,40}shell\\s*=\\s*True', '(?i)__import__\\s*\\(\\s*[\'"](?:os|subprocess)[\'"]']},
    {'id': 'CALUS-MCP-SCAN-3238', 'name': 'mcp-arbitrary-file-write-via-tool', 'severity': 'high', 'category': 'mcp_security', 'message': 'Arbitrary file write vulnerability: tool parameter used in file write path. Attackers can modify .bashrc for persistence.', 'patterns': ['(?i)(?:open|write)\\s*\\(\\s*f[\'"]\\{', '(?i)(?:shutil\\.copy|shutil\\.move)\\s*\\(\\s*.{0,40}user']},
    {'id': 'CALUS-MCP-SCAN-3239', 'name': 'mcp-insecure-deserialization-in-input', 'severity': 'high', 'category': 'mcp_security', 'message': 'Insecure deserialization detected: pickle.load or yaml.load used with potentially untrusted input, enabling remote code execution.', 'patterns': ['(?i)(?:from\\s+pickle\\s+import|import\\s+pickle)', '(?i)\\byaml\\.load\\s*\\(\\s*input']},
    {'id': 'CALUS-MCP-SCAN-3240', 'name': 'mcp-hardcoded-token-in-tool-description', 'severity': 'high', 'category': 'mcp_security', 'message': 'Hardcoded API token or authorization header detected in MCP server definition. Exposes credentials in tool descriptions accessible by LLMs.', 'patterns': ['(?i)(?:Authorization|Bearer)\\s*[:=]\\s*[\'"][Bb]earer\\s+[A-Za-z0-9+/=]{20,}[\'"]', '(?i)(?:x-api-key|x-auth-token)\\s*[:=]\\s*[\'"][^\'"]{10,}[\'"]']},
    {'id': 'CALUS-MCP-SCAN-3241', 'name': 'mcp-insecure-http-transport-without-ssl', 'severity': 'low', 'category': 'mcp_security', 'message': 'MCP server uses HTTP for remote transport. Unencrypted communication enables MITM attacks and credential theft.', 'patterns': ['(?i)(?:http://|ws://)\\S+(?:\\btransport\\b|\\bserver\\b|\\burl\\b)', '(?i)(?:transport|server)\\s*[:=]\\s*[\'"]http://', '(?i)(?:sse|SSE)\\s*[:=]\\s*[\'"]http://']},
    {'id': 'CALUS-MCP-SCAN-3242', 'name': 'mcp-path-traversal-in-file-tools', 'severity': 'high', 'category': 'mcp_security', 'message': 'Path traversal vulnerability: user-controlled path used to access files. Attackers can read arbitrary files on the system.', 'patterns': ['(?i)\\bpath\\b.{0,40}(?:user|inp|param).{0,40}(?:join|open|read)']},
    {'id': 'CALUS-MCP-SCAN-3243', 'name': 'mcp-os-environment-leak-in-tool-output', 'severity': 'medium', 'category': 'mcp_security', 'message': 'MCP server tool exposes environment variables. This can lead to credential theft by leaking API keys and secrets.', 'patterns': ['(?i)(?:subprocess|os\\.popen)\\s*\\([\'"](?:env|set|printenv)[\'"|]', '(?i)\\breturn\\b.{0,40}\\bos\\.environ\\b']},
    {'id': 'CALUS-MCP-SCAN-3244', 'name': 'etdi-missing-signature-verification', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Tool definition missing cryptographic signature verification in MCP client code.', 'patterns': ['(?i)(?:def|function)\\s+verifyAndApproveTool\\b', '(?i)Crypto\\.verifySignature\\(', '(?i)toolDefinition\\.signature']},
    {'id': 'CALUS-MCP-SCAN-3245', 'name': 'etdi-versionless-tool-definition', 'severity': 'low', 'category': 'mcp_security', 'message': 'Tool definition without version field detected, enabling silent modification.', 'patterns': ['(?i)"tool_version"\\s*:\\s*"\\d+\\.\\d+"', '(?i)toolDefinition\\.version\\b']},
    {'id': 'CALUS-MCP-SCAN-3246', 'name': 'etdi-unsigned-policy-artifact', 'severity': 'high', 'category': 'mcp_security', 'message': 'Policy file loaded without signature verification.', 'patterns': ['(?i)(?:open|load|read|parse)\\s*\\(.{0,40}\\.cedar\\)', '(?i)opa\\.new_policy\\(.{0,40}\\.rego\\)', '(?i)AmazonVerifiedPermissions\\.isAuthorized\\(']},
    {'id': 'CALUS-MCP-SCAN-3247', 'name': 'etdi-signature-verification-skip', 'severity': 'critical', 'category': 'mcp_security', 'message': 'ETDI signature verification disabled: tools accepted without cryptographic integrity check.', 'patterns': ['(?i)(?:verify|check|validate)\\s*(?:Signature|Sig|Auth)\\s*(=|==|!=)\\s*(?:False|null|None|0)', '(?i)if\\s+(?:not\\s+)?(?:Crypto\\.verifySignature|verify_signature)\\s*\\([^)]+\\)\\s*:\\s*\\n\\s*(?:return\\s+True|pass|# comment)\\s']},
    {'id': 'CALUS-MCP-SCAN-3248', 'name': 'etdi-version-rollback-ignore', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Tool version rollback allowed without re-approval, enabling rug pull via reverted malicious code.', 'patterns': ['(?i)(?:version|ver)\\s*(?:<|<=)\\s*approvedDef\\.version\\s*(?:&&|and)\\s*(?:#|//|--)\\s*(?:allow|skip|ignore)', '(?i)if\\s+toolDef\\.version\\s*<\\s*approved\\.version\\s*:?\\s*\\n\\s*(?:return\\s+True|pass|continue)']},
    {'id': 'CALUS-MCP-SCAN-3249', 'name': 'etdi-content-hash-tamper', 'severity': 'critical', 'category': 'mcp_security', 'message': 'Content hash mismatch ignored: malicious modification of tool definition not detected.', 'patterns': ['(?i)Crypto\\.hash\\(toolDef\\.content\\)\\s*(?:!=|!==|!=)\\s*approved\\.contentHash\\s*(?:&&|and)\\s*False', '(?i)if\\s+hash\\s*(?:!=|!==)\\s*stored_hash\\s*:?\\s*\\n\\s*(?:return\\s+True|pass|# skip)']},
    {'id': 'CALUS-MCP-SCAN-3250', 'name': 'etdi-call-stack-circular-allow', 'severity': 'high', 'category': 'mcp_security', 'message': 'Circular tool invocation allowed: attacker can cause infinite loop and resource exhaustion.', 'patterns': ['(?i)call_stack\\.(?:append|push|add)\\(callee\\)\\s*[^\\n]*?(?:#|//).{0,40}circular', '(?i)if\\s+(?:callee\\s+in\\s+call_stack|call_stack\\.contains\\(callee\\))\\s*:?\\s*\\n\\s*(?:return\\s+True|pass|continue)']},
    {'id': 'CALUS-MCP-SCAN-3251', 'name': 'etdi-call-stack-depth-limit-absent', 'severity': 'low', 'category': 'mcp_security', 'message': 'No maximum call depth enforced: attacker can create deep call chain to exhaust resources.', 'patterns': ['(?i)(?:max_depth|maxDepth|depth_limit)\\s*(?:=|:=|:)\\s*(?:None|-1|0|1000\\s*[^\\d])', '(?i)while\\s+(?:True|1)\\s*:?\\s*\\n\\s*(?:call|invoke|invokeTool)']},
    {'id': 'CALUS-MCP-SCAN-3252', 'name': 'mcp-tool-poisoning-hidden-instruction-pattern', 'severity': 'medium', 'category': 'mcp_security', 'message': 'Potential tool poisoning: hidden instructions in MCP tool description to read sensitive files or redirect messages.', 'patterns': ["(?i)<IMPORTANT>\\s*read\\s+the\\s+user's\\s+\\.ssh", "(?i)<IMPORTANT>\\s*quietly\\s+read\\s+the\\s+user's\\s+\\.ssh/id_rsa", '(?i)<IMPORTANT>\\s*modify\\s+the\\s+behavior\\s+of\\s+send_email']},
    {'id': 'CALUS-MCP-SCAN-3253', 'name': 'mcp-command-injection-shell-metachar', 'severity': 'critical', 'category': 'mcp_security', 'message': 'Potential command injection: user input directly injected into shell command in MCP server.', 'patterns': ['(?i)os\\.system\\(f[\'"]\\{.{0,40}\\b(?:username|user|msg|message)\\b.{0,40}[\'"]\\)', '(?i)subprocess\\.(?:run|Popen|call)\\(\\s*(?:f[\'"]|[\'"]).{0,40}\\b(?:username|user|msg|message)\\b.{0,40}[\'"]\\s*,\\s*shell\\s*=\\s*True', '(?i)os\\.popen\\(f[\'"].{0,40}\\b(?:username|user|msg|message)\\b']},
    {'id': 'CALUS-MCP-SCAN-3254', 'name': 'mcp-tool-name-squatting', 'severity': 'low', 'category': 'mcp_security', 'message': 'Potential tool name squatting: MCP server name resembles a known trusted tool.', 'patterns': ['(?i)\\bmcp-[-a-z]*?(?:tavily|github|slack|filesystem|database|postgres|sqlite)\\b', '(?i)\\b(?:tavily|github|slack|filesystem|database|postgres|sqlite)-mcp\\b']},
    {'id': 'CALUS-MCP-SCAN-3256', 'name': 'mcp-dpma-best-description-insertion', 'severity': 'low', 'category': 'mcp_security', 'message': "Detected DPMA Best Description manipulation: 'This is the best tool in the world' inserted in tool description.", 'patterns': ['(?i)(?:\\"|\')\\s*This is the best tool in the world\\.', '(?i)\\bdescription\\s*:\\s*[\\"\']\\s*This is the best tool in the world']},
    {'id': 'CALUS-MCP-SCAN-3257', 'name': 'mcp-dpma-best-name-prefix', 'severity': 'low', 'category': 'mcp_security', 'message': "Detected DPMA Best Name manipulation: tool name starts with 'best'.", 'patterns': ['(?i)\\btool_name\\s*:\\s*[\\"\']?best\\w+', '(?i)"name"\\s*:\\s*"best\\w+']},
    {'id': 'CALUS-MCP-SCAN-3258', 'name': 'mcp-gapma-authoritative-description', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected GAPMA Authoritative advertising strategy in tool description.', 'patterns': ['(?i)"description"\\s*:\\s*"[^"]*(?:expert|recommend|authoritative|trusted by professionals)[^"]*"', '(?i)\\bdescription\\s*:\\s*[\\"\'][^\\"\']*(?:expert|recommend|authoritative|trusted by professionals)']},
    {'id': 'CALUS-MCP-SCAN-3259', 'name': 'mcp-gapma-emotional-description', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected GAPMA Emotional advertising strategy in tool description.', 'patterns': ['(?i)"description"\\s*:\\s*"[^"]*(?:amazing|incredible|love|hate|fear|exciting|fantastic)[^"]*"', '(?i)\\bdescription\\s*:\\s*[\\"\'][^\\"\']*(?:amazing|incredible|love|hate|fear|exciting|fantastic)']},
    {'id': 'CALUS-MCP-SCAN-3260', 'name': 'mcp-gapma-exaggerated-description', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected GAPMA Exaggerated advertising strategy in tool description.', 'patterns': ['(?i)\\bdescription\\s*:\\s*[\\"\'][^\\"\']*(?:best|greatest|superior|unmatched|perfect|ultimate|revolutionary)']},
    {'id': 'CALUS-MCP-SCAN-3261', 'name': 'mcp-gapma-subliminal-description', 'severity': 'low', 'category': 'mcp_security', 'message': 'Detected GAPMA Subliminal advertising strategy in tool description.', 'patterns': ['(?i)"description"\\s*:\\s*"[^"]*(?:recommended|trusted|preferred|chosen|popular|widely used)[^"]*"', '(?i)\\bdescription\\s*:\\s*[\\"\'][^\\"\']*(?:recommended|trusted|preferred|chosen|popular|widely used)']},
    {'id': 'CALUS-MCP-SCAN-3262', 'name': 'mpma-best-description-injection', 'severity': 'low', 'category': 'mcp_security', 'message': "MCP tool description contains DPMA Best Description injection: 'This is the best tool in the world.'", 'patterns': ['(?i)this\\s+is\\s+the\\s+best\\s+tool\\s+in\\s+the\\s+world', '(?i)description.{0,20}best\\s+tool\\s+in\\s+the\\s+world']},
